  '[{"text":"Share HubSpot object and workflow change recommendations with Michael and team (52:14)","completed":false},{"text":"Develop and deliver website plan document including architecture, messaging, URL strategy, and page templates (31:07)","completed":false},{"text":"Set up weekly recurring meeting with Michael starting first week of December on Tuesdays at 10 AM, send calendar invites (51:32)","completed":false},{"text":"Provide brand/website rebranding research and recommendations regarding KTC Search versus existing branding (23:59)","completed":false},{"text":"Initiate content plan development detailing show names, themes, target audience, and publishing cadence (40:35)","completed":false},{"text":"Facilitate setup of portfolio total platform access for Michael with single sign-on and goal loading (50:30)","completed":false},{"text":"Coordinate with Michael and internal teams on notification and logistics for migrating website to HubSpot (52:14)","completed":false},{"text":"Collaborate on HubSpot features and workflow structure aligning marketing and sales objectives (09:05)","completed":false},{"text":"Assist in defining sales vs marketing roles for communications and sequencing within HubSpot (10:00)","completed":false},{"text":"Assist in content engine creation and management focusing on guest interviews, market topics, and stealth content scheduling (34:12)","completed":false},{"text":"Support in packaging portfolio talent trends report and leadership gap assessment for ABM campaigns (43:00)","completed":false},{"text":"Provide disallowed target companies and contacts list to avoid marketing overlaps (48:32)","completed":false},{"text":"Facilitate access and share contacts from Zoom database for use in campaigns (33:55)","completed":false},{"text":"Identify internal point(s) of contact or authorize communication with Ryan regarding website migration preparations (52:14)","completed":false},{"text":"Engage with selected industry experts and board members to support industry insights and content development (45:17)","completed":false}]'::jsonb,
