-- Meeting: Sync up with Barb (2025-11-21 19:30:00+00)
WITH new_meeting AS (
  INSERT INTO compass_meetings (contract_id, meeting_date, source, external_id, title, participants, duration_seconds, recording_url, transcript, sentiment, raw_metadata, created_at, updated_at)
  VALUES (
    '52b3ee0f-cbad-4031-a387-79ecb54874fb',
    '2025-11-21 19:30:00+00',
    'fireflies',
    '01KAEFFPA76B5RW065H65A5Z11',
    'Sync up with Barb',
    '{"Tristan Pelligrino","vivian","bwillans"}'::text[],
    3895,
    'https://us02web.zoom.us/j/81173743169?pwd=fdhWr17Y8OSDIxAa0azAeWjIfvQJcq.1',
    '{"id":"01KAEFFPA76B5RW065H65A5Z11","title":"Sync up with Barb","summary":{"notes":"## **HubSpot and Salesforce Integration Strategy**\n\nThe team agreed on aligning HubSpot and Salesforce taxonomies to ensure seamless data flow and reporting consistency.\n\n- **Vivian emphasized the need for matching taxonomy between HubSpot and Salesforce fields** to prevent confusion and manual guesswork by BDRs like Blake (12:51)  \n    - She stressed that source fields in both systems must correspond to maintain clarity on lead origins  \n    - Tristan confirmed opportunity-level source fields can be automated to sync from HubSpot to Salesforce, reducing manual errors  \n    - Barb and Vivian agreed to involve Kyle and Maria to vet workflow changes and confirm technical alignment before rollout  \n    - Successful integration will ensure accurate management reports in 2026 on lead sources split by sales vs. marketing channels  \n\n- **The team planned a review cycle involving Kyle, Maria, and Blake to finalize lifecycle stage definitions and data flows** (17:19)  \n    - Vivian recommended sharing the HubSpot implementation plan for stakeholder feedback with a deadline and follow-up meeting  \n    - Barb will coordinate meetings to socialize changes and capture buy-in, especially from BDRs impacted by new workflows  \n    - Tristan highlighted the need to align business process definitions (e.g., MQL, SQL) before final HubSpot configuration  \n    - This alignment is critical to avoid data gaps and ensure smooth operational handoffs between marketing and sales  \n\n- **Data cleanup and database segmentation were prioritized to curate a clean 17,000-contact marketing database** (23:35)  \n    - Barb and Vivian identified key customer segments including WIMS existing, WIMS net new, and industrial customers to prioritize  \n    - Tristan proposed cleansing Salesforce records first using email validation and other criteria, then syncing clean data into HubSpot  \n    - Vivian agreed to take first pass on field inventory to determine segmentation criteria, targeting 5-8 fields for prioritization  \n    - Target date for initial cleanup and sync readiness is the **first week of December** to enable December configuration and testing  \n\n## **Lead and Engagement Data Retention**\n\nMaintaining engagement data and behavioral history during migration is critical to avoid losing valuable lead context.\n\n- **Barb raised concerns about losing historical lead scoring, activities, and comments from Marketo during transfer to HubSpot and Salesforce** (47:31)  \n    - She requested a solution to preserve lead behavior data to maintain marketing and sales context  \n    - Tristan proposed storing historical notes and activities in custom HubSpot fields or event logs that sync back to Salesforce  \n    - This approach ensures BDRs like Blake retain full visibility on lead history for better engagement and follow-up  \n    - Barb emphasized this as an opportunity to enhance nurture programs beyond MQL conversion  \n\n- **The team discussed approach to preserving dynamic marketing lists and engagement status** (53:17)  \n    - Barb confirmed key dynamic lists exist in Marketo with engaged contacts that must be accurately replicated in HubSpot  \n    - Vivian noted the importance of verifying list membership mapping between Marketo and Salesforce to avoid data loss  \n    - Tristan suggested either recreating dynamic lists in HubSpot based on criteria or migrating static snapshots as needed  \n    - This will ensure continuity in targeting and segmentation post-migration, preserving marketing effectiveness  \n\n## **Website and Form Transition**\n\nA smooth transition of web forms and hosting environment is planned to support HubSpot adoption without disrupting user experience.\n\n- **James, responsible for WordPress hosting, will facilitate form recreation and deployment for HubSpot forms** (35:20)  \n    - Hosting environment on WP Engine is confirmed and ready for test pages with HubSpot forms embedded via code  \n    - Barb will schedule a short meeting to align James with upcoming form changes and resource updates on the website  \n    - Tristan emphasized creating a staging environment to safely test form changes before live deployment, improving quality assurance  \n    - This will support a phased cutover from Marketo forms with minimal disruption to referral and customer service teams  \n\n- **Vivian highlighted multiple referral forms to be rebuilt in HubSpot and communicated to respective teams** (44:10)  \n    - Four key referral forms (Hawk, customer service, professional services, and in-market) will be replaced with HubSpot versions  \n    - Teams using these forms will receive updated links and workflows to ensure continuity and capture data correctly  \n    - Tristan noted that if forms remain embedded on the same URLs, the swap can be seamless without user experience changes  \n    - Vivian volunteered to coordinate with these teams to confirm no needed form modifications during transition  \n\n## **Marketing Campaign Timing and Communication**\n\nThe team established flexible timing guidelines to maintain marketing momentum during the December-to-January transition.\n\n- **There is no formal marketing blackout period during the December-January cutover, allowing pre-promotion of events like webinars** (39:08)  \n    - Barb and Colin are currently using Constant Contact to start moving drip campaigns before HubSpot fully takes over  \n    - Tristan confirmed that data syncing and routing through Marketo can continue during this period without blocking promotions  \n    - This approach avoids delays in lead generation and nurturing despite backend system changes  \n    - The ability to promote 3-4 weeks in advance supports timely event attendance and pipeline development  \n\n- **Vivian will draft a communications plan for rollout and change management** (43:50)  \n    - Plan will cover form transitions, workflow changes, and stakeholder buy-in to minimize confusion and ensure smooth adoption  \n    - Inclusion of referral form updates and user education is a key component  \n    - Barb and Tristan will support this plan with technical and operational insights  \n    - Effective communication will reduce risk of lost leads or user frustration during migration  \n\n## **Opportunity Stage-Based Marketing Segmentation**\n\nMarketing will tailor communications based on sales opportunity stages to maximize relevance and engagement.\n\n- **Taylor, sales team lead, requested marketing continue engagement throughout opportunity stages from 10% to 100%** (57:03)  \n    - Marketing will segment contact lists by opportunity stage to deliver stage-appropriate content (e.g., educational early, customer-focused later)  \n    - Vivian sees this as enabling multi-touch attribution and better tracking of marketing influence on deal progression  \n    - Tristan confirmed HubSpot can map opportunity stages at the account level to dynamically include/exclude contacts from campaigns  \n    - This strategy supports sustained nurturing and higher conversion rates through the sales funnel  \n\n- **Tracking marketing activities and their timing relative to opportunity stages will provide valuable insights** (59:34)  \n    - The team plans to review account activity timelines to understand what marketing influenced opportunity movement  \n    - This analysis will help optimize campaigns and resource allocation for future pipeline acceleration  \n    - Integrating activity data between HubSpot and Salesforce will create a comprehensive view of marketing impact  \n    - Barb and Vivian emphasized the importance of not just capturing leads but also measuring ongoing engagement quality  \n\n## **Timeline and Next Steps**\n\nThe project is on track for a January cutover with key milestones focused on alignment, data cleanup, and testing.\n\n- **HubSpot instance was received mid-November, with December dedicated to configuration and testing** (01:02:08)  \n    - Barb and Vivian will provide updated lifecycle stage definitions and feedback from stakeholder groups in upcoming meetings  \n    - Tristan plans to coordinate with Kyle and Maria for technical alignment and final field mapping before enabling sync  \n    - Data cleansing efforts targeting the 17,000-contact database aim for completion shortly after Thanksgiving, early December  \n    - The team is confident they are not behind schedule and expect to start real product testing soon  \n\n- **Vivian committed to drafting segmentation criteria and database field inventory for review at next Friday’s meeting** (01:03:32)  \n    - Barb and Tristan will support with technical guidance and coordinate stakeholder communications  \n    - Next meeting will include Kyle and Maria to finalize definitions and address any red flags before go-live  \n    - Continued collaboration and strong partnership were highlighted as key factors keeping the project on track  \n    - The team will maintain close communication to solve new issues as they arise during testing and rollout phases","outline":null,"keywords":["HubSpot implementation","Salesforce sync","lead source taxonomy","data cleansing","Marketo migration","lifecycle stages"],"overview":"- **Integration Strategy:** Align HubSpot and Salesforce taxonomies for seamless data flow and consistent reporting; critical for lead source clarity.\n\n- **Data Cleanup:** Prioritize cleaning a 17,000-contact database, targeting completion by the first week of December for effective testing.\n\n- **Engagement Data Preservation:** Ensure historical lead scoring and activities are retained during migration for better sales and marketing context.\n\n- **Form Transition:** Rebuild key referral forms in HubSpot without disruptions to user experience; staging environment will facilitate safe testing.\n\n- **Marketing Timing:** No blackout period for marketing during transition; ongoing promotions will support lead generation and event attendance.\n\n- **Opportunity Stage Segmentation:** Tailor marketing based on sales opportunity stages to enhance engagement and optimize resource allocation for sales pipeline.","action_items":"\n**Barb Willans**\nFacilitate scheduling and stakeholder communication for meetings with Kyle and Maria to review HubSpot implementation plan and lifecycle stages (17:58)\nSet up meeting with James to discuss website form replacements and WIMS resource updates (37:32)\nShare life cycle stage definition updates with Tristan’s team for feedback (20:21)\nConfirm embedding locations of referral forms in WordPress for form replacement planning (45:22)\nProvide Graziti’s list slugs for marketing seed lists to Tristan’s team for review (50:26)\n\n**Vivian**\nReview Salesforce fields to identify key segmentation attributes; coordinate first-pass database curation with Barb (26:30)\nVolunteer to lead communications outreach to referral form owners to verify requirements ahead of migration (44:15)\nDraft communications plan for change management and form migrations (42:52)\nPrepare a list of feature and process needs related to lifecycle stages and database segments to share with stakeholders (01:03:32)\n\n**Tristan Pelligrino**\nProvide screenshots or equivalent of Kyle’s Miro board to Barb and Vivian (07:42)\nDefine and plan custom field mapping and sync automation for lead and opportunity sources between HubSpot and Salesforce (12:51)\nGuide data cleansing approach based on email validation and segmentation, coordinate with Kyle and Maria for Salesforce data clean-up strategy (26:09)\nRecommend mechanism for preserving historical Marketo notes and activities in HubSpot and Salesforce as event logs or custom fields (31:30)\nCoordinate with Kyle and Maria on Salesforce custom code changes for lead to opportunity conversion sync (15:36)\nDefine and support testing approach for HubSpot sync with Salesforce and Marketo database cut-off timing, targeting first week of December start for data cleanup and configuration (29:11)\nPlan for post-cleanup syncing and reconciliation of contact data between systems followed by validation checks (22:38)\nCreate test WordPress pages with HubSpot forms and work with James to implement seamless form swaps (35:20)\nPrepare follow-up meeting with Kyle and Maria to review overall HubSpot implementation and lifecycle alignment (01:01:50)\n\n**Guille Santana**\nCollaborate with Tristan on creating workflows for data field syncs and marketing event logs integration \n"},"duration":64.91000366210938,"speakers":[{"id":0,"name":"Tristan Pelligrino"},{"id":1,"name":"vivian"},{"id":2,"name":"bwillans"}],"sentences":[{"text":"Vivian''s on the train.","index":0,"end_time":1.28,"speaker_id":0,"start_time":0.08,"speaker_name":"Tristan Pelligrino"},{"text":"This is some, some next level commitment here, but we, we are good.","index":1,"end_time":7.36,"speaker_id":0,"start_time":1.28,"speaker_name":"Tristan Pelligrino"},{"text":"Hi, everyone.","index":2,"end_time":8.64,"speaker_id":1,"start_time":7.84,"speaker_name":"vivian"},{"text":"I''m now in a.","index":3,"end_time":10.24,"speaker_id":1,"start_time":9.2,"speaker_name":"vivian"},{"text":"My brother''s car.","index":4,"end_time":11.4,"speaker_id":1,"start_time":10.4,"speaker_name":"vivian"},{"text":"And, and so, yeah, yeah, so yeah, I''m, I''m in transit.","index":5,"end_time":15.36,"speaker_id":1,"start_time":11.4,"speaker_name":"vivian"},{"text":"Planes, trains and automobiles.","index":6,"end_time":18.32,"speaker_id":0,"start_time":16.48,"speaker_name":"Tristan Pelligrino"},{"text":"Very well.","index":7,"end_time":20.48,"speaker_id":1,"start_time":18.32,"speaker_name":"vivian"},{"text":"Hopefully you stay safe during this conversation and get to where you need to go.","index":8,"end_time":25.2,"speaker_id":0,"start_time":20.48,"speaker_name":"Tristan Pelligrino"},{"text":"But thanks, thanks for joining, Vivian.","index":9,"end_time":26.72,"speaker_id":0,"start_time":25.2,"speaker_name":"Tristan Pelligrino"},{"text":"I know Barbara added you to the conversation.","index":10,"end_time":29.6,"speaker_id":0,"start_time":26.72,"speaker_name":"Tristan Pelligrino"},{"text":"We have here a couple key things.","index":11,"end_time":33.02,"speaker_id":0,"start_time":29.6,"speaker_name":"Tristan Pelligrino"},{"text":"I know, Barb, we sent over some documentation with where we''re headed with a couple of the projects that we have.","index":12,"end_time":39.5,"speaker_id":0,"start_time":33.26,"speaker_name":"Tristan Pelligrino"},{"text":"And like we mentioned, you know, on the HubSpot implementation side, kind of, it should feel like a draft that we want to cover some, some key decision points.","index":13,"end_time":48.54,"speaker_id":0,"start_time":40.3,"speaker_name":"Tristan Pelligrino"},{"text":"Right.","index":14,"end_time":48.94,"speaker_id":0,"start_time":48.54,"speaker_name":"Tristan Pelligrino"},{"text":"And then there''s the other component on the website where we were looking for some analysis and then some recommendations on where we would go with, especially on the whim side that we had talked about.","index":15,"end_time":60.34,"speaker_id":0,"start_time":49.42,"speaker_name":"Tristan Pelligrino"},{"text":"So that''s what we had on tap.","index":16,"end_time":62.38,"speaker_id":0,"start_time":60.5,"speaker_name":"Tristan Pelligrino"},{"text":"I know you just sent a good email to us, Barb, with a lot of stuff in there.","index":17,"end_time":67.94,"speaker_id":0,"start_time":62.38,"speaker_name":"Tristan Pelligrino"},{"text":"Sorry about that.","index":18,"end_time":71.38,"speaker_id":0,"start_time":68.74,"speaker_name":"Tristan Pelligrino"},{"text":"That''s great.","index":19,"end_time":72.1,"speaker_id":0,"start_time":71.38,"speaker_name":"Tristan Pelligrino"},{"text":"Do you want to start there?","index":20,"end_time":74.5,"speaker_id":0,"start_time":72.9,"speaker_name":"Tristan Pelligrino"},{"text":"Because I also see there''s comments in the PDFs as well that you sent back.","index":21,"end_time":78.9,"speaker_id":0,"start_time":74.66,"speaker_name":"Tristan Pelligrino"},{"text":"So how would you all like to go through the material here?","index":22,"end_time":82.66,"speaker_id":0,"start_time":78.98,"speaker_name":"Tristan Pelligrino"},{"text":"I, I like a couple of things, maybe introductions, I think, because we have a new member of our team.","index":23,"end_time":90.71,"speaker_id":2,"start_time":84.75,"speaker_name":"bwillans"},{"text":"Oh, got you.","index":24,"end_time":91.47,"speaker_id":0,"start_time":90.71,"speaker_name":"Tristan Pelligrino"},{"text":"Yes.","index":25,"end_time":92.15,"speaker_id":0,"start_time":91.71,"speaker_name":"Tristan Pelligrino"},{"text":"Vivian.","index":26,"end_time":92.63,"speaker_id":2,"start_time":92.15,"speaker_name":"bwillans"},{"text":"Yeah, so Vivian''s my boss, so just.","index":27,"end_time":95.63,"speaker_id":2,"start_time":92.63,"speaker_name":"bwillans"},{"text":"And Colin couldn''t make it today.","index":28,"end_time":96.87,"speaker_id":2,"start_time":95.63,"speaker_name":"bwillans"},{"text":"He went on much.","index":29,"end_time":98.43,"speaker_id":2,"start_time":96.87,"speaker_name":"bwillans"},{"text":"Deserved vacation already.","index":30,"end_time":99.79,"speaker_id":2,"start_time":98.43,"speaker_name":"bwillans"},{"text":"So he''s not here, but he does have all your notes.","index":31,"end_time":102.51,"speaker_id":2,"start_time":99.87,"speaker_name":"bwillans"},{"text":"And, and so I think we start there and then from that maybe we just go through.","index":32,"end_time":107.71,"speaker_id":2,"start_time":102.51,"speaker_name":"bwillans"},{"text":"I don''t think we have to open up the PDF so much because it was documented in the email, but I didn''t want to lead the witness here.","index":33,"end_time":114.86,"speaker_id":2,"start_time":107.79,"speaker_name":"bwillans"},{"text":"I, I really want, you know, Vivian to be able to speak to, you know, her, her feedback first, I would think, and then we can go over some tactical stuff.","index":34,"end_time":126.02,"speaker_id":2,"start_time":114.86,"speaker_name":"bwillans"},{"text":"So I think that that would be my priority list.","index":35,"end_time":128.699,"speaker_id":2,"start_time":126.02,"speaker_name":"bwillans"},{"text":"All right, cool.","index":36,"end_time":129.7,"speaker_id":0,"start_time":128.699,"speaker_name":"Tristan Pelligrino"},{"text":"Well, yeah, Vivian, just.","index":37,"end_time":130.94,"speaker_id":0,"start_time":129.7,"speaker_name":"Tristan Pelligrino"},{"text":"Sorry to jump in, but yeah, a little bit of background.","index":38,"end_time":133.58,"speaker_id":0,"start_time":131.02,"speaker_name":"Tristan Pelligrino"},{"text":"Colin''s on vacation, so he''s, he''s.","index":39,"end_time":136.62,"speaker_id":0,"start_time":133.74,"speaker_name":"Tristan Pelligrino"},{"text":"I think he''s already traveled to where he''s going, so he''s, he''s out for a few days, but we wanted to keep things rolling, so that''s why I jumped in.","index":40,"end_time":144.3,"speaker_id":0,"start_time":137.02,"speaker_name":"Tristan Pelligrino"},{"text":"But Collins, our head of accounts, and then Guille is one of our strategists.","index":41,"end_time":147.7,"speaker_id":0,"start_time":144.3,"speaker_name":"Tristan Pelligrino"},{"text":"And Guille, I think you''ve met Barb before, but maybe not okay.","index":42,"end_time":151.82,"speaker_id":0,"start_time":147.7,"speaker_name":"Tristan Pelligrino"},{"text":"Last week.","index":43,"end_time":152.38,"speaker_id":2,"start_time":151.82,"speaker_name":"bwillans"},{"text":"Yeah.","index":44,"end_time":152.94,"speaker_id":2,"start_time":152.46,"speaker_name":"bwillans"},{"text":"Good to see you again.","index":45,"end_time":154.06,"speaker_id":2,"start_time":153.1,"speaker_name":"bwillans"},{"text":"So that''s where we are.","index":46,"end_time":155.82,"speaker_id":0,"start_time":154.38,"speaker_name":"Tristan Pelligrino"},{"text":"YE has been testing some things already from Marketa to Salesforce, and Kyle and I have of course looked at a lot of this stuff.","index":47,"end_time":161.9,"speaker_id":0,"start_time":155.82,"speaker_name":"Tristan Pelligrino"},{"text":"But we have three eyes on the project and we''re working together to solve some of these key data challenges that we have and figure out the best approach to take.","index":48,"end_time":172.7,"speaker_id":0,"start_time":161.9,"speaker_name":"Tristan Pelligrino"},{"text":"So that''s what we''re looking at.","index":49,"end_time":174.58,"speaker_id":0,"start_time":172.78,"speaker_name":"Tristan Pelligrino"},{"text":"Great.","index":50,"end_time":175.86,"speaker_id":2,"start_time":175.46,"speaker_name":"bwillans"},{"text":"And maybe Vivian, just let Gay know who you are and vice versa.","index":51,"end_time":180.74,"speaker_id":2,"start_time":176.18,"speaker_name":"bwillans"},{"text":"I think it''s going to be a good level set.","index":52,"end_time":182.9,"speaker_id":2,"start_time":180.74,"speaker_name":"bwillans"},{"text":"Yeah.","index":53,"end_time":183.78,"speaker_id":1,"start_time":183.38,"speaker_name":"vivian"},{"text":"So, team, I''m.","index":54,"end_time":184.74,"speaker_id":1,"start_time":183.78,"speaker_name":"vivian"},{"text":"I''m the director of marketing, but with respect to this project, Barb is the boss of me.","index":55,"end_time":190.42,"speaker_id":1,"start_time":184.74,"speaker_name":"vivian"},{"text":"So Barb is like, really the champion of this project and I just wanted to join in just as an extra set of eyes in terms of, like, how HubSpot kind of touches different groups and whatnot.","index":56,"end_time":204.54,"speaker_id":1,"start_time":190.58,"speaker_name":"vivian"},{"text":"So an alternative point of view and.","index":57,"end_time":206.24,"speaker_id":1,"start_time":204.54,"speaker_name":"vivian"},{"text":"And also just to support.","index":58,"end_time":207.6,"speaker_id":1,"start_time":206.24,"speaker_name":"vivian"},{"text":"So I''m going to be here to support Barb and.","index":59,"end_time":210.48,"speaker_id":1,"start_time":207.84,"speaker_name":"vivian"},{"text":"And you guys in whatever you guys need to get to the finish line because there''s a pretty significant amount of work.","index":60,"end_time":217.32,"speaker_id":1,"start_time":210.88,"speaker_name":"vivian"},{"text":"But I have to say, I am so thrilled.","index":61,"end_time":221.6,"speaker_id":1,"start_time":217.32,"speaker_name":"vivian"},{"text":"When I review all of the documents, there is such clarity in the way that you guys do things and.","index":62,"end_time":226.6,"speaker_id":1,"start_time":221.6,"speaker_name":"vivian"},{"text":"And articulate what needs to be done.","index":63,"end_time":228.4,"speaker_id":1,"start_time":226.6,"speaker_name":"vivian"},{"text":"And some of that repetition was also very helpful.","index":64,"end_time":231.44,"speaker_id":1,"start_time":229.04,"speaker_name":"vivian"},{"text":"So.","index":65,"end_time":231.83,"speaker_id":1,"start_time":231.67,"speaker_name":"vivian"},{"text":"So that it''s really embedded in a clear understanding on what needs to be done.","index":66,"end_time":235.62,"speaker_id":1,"start_time":231.98,"speaker_name":"vivian"},{"text":"So thanks for that.","index":67,"end_time":236.54,"speaker_id":1,"start_time":235.62,"speaker_name":"vivian"},{"text":"It was an enjoyable read because it was.","index":68,"end_time":240.62,"speaker_id":1,"start_time":237.82,"speaker_name":"vivian"},{"text":"Oh, gosh, that''s embarrassing.","index":69,"end_time":241.94,"speaker_id":0,"start_time":240.62,"speaker_name":"Tristan Pelligrino"},{"text":"Hopefully it wasn''t so clear.","index":70,"end_time":243.5,"speaker_id":1,"start_time":241.94,"speaker_name":"vivian"},{"text":"It was so clear.","index":71,"end_time":244.78,"speaker_id":1,"start_time":243.74,"speaker_name":"vivian"},{"text":"So, yeah, I''m excited to join this awesome team.","index":72,"end_time":249.34,"speaker_id":1,"start_time":245.82,"speaker_name":"vivian"},{"text":"Well, very cool.","index":73,"end_time":250.78,"speaker_id":0,"start_time":249.98,"speaker_name":"Tristan Pelligrino"},{"text":"Appreciate that.","index":74,"end_time":251.3,"speaker_id":0,"start_time":250.78,"speaker_name":"Tristan Pelligrino"},{"text":"Yeah, Guy really did.","index":75,"end_time":253.22,"speaker_id":0,"start_time":251.3,"speaker_name":"Tristan Pelligrino"},{"text":"I would say 99.9% of that guy.","index":76,"end_time":255.5,"speaker_id":0,"start_time":253.22,"speaker_name":"Tristan Pelligrino"},{"text":"Maybe I did 0.1%, but no, we''ve done a lot of testing.","index":77,"end_time":260.5,"speaker_id":0,"start_time":255.5,"speaker_name":"Tristan Pelligrino"},{"text":"But yeah, has done a good job documenting and making sure that we map it out.","index":78,"end_time":266.28,"speaker_id":0,"start_time":260.5,"speaker_name":"Tristan Pelligrino"},{"text":"So that''s why we wanted to have her on the call.","index":79,"end_time":269.16,"speaker_id":0,"start_time":266.44,"speaker_name":"Tristan Pelligrino"},{"text":"And then I know, you know, Colin, I''ve been in a lot of the strategic conversations we''ve had with, you know, sales side and then Marketo folks.","index":80,"end_time":277.52,"speaker_id":0,"start_time":270.04,"speaker_name":"Tristan Pelligrino"},{"text":"So we''re in a pretty good spot.","index":81,"end_time":279.56,"speaker_id":0,"start_time":277.52,"speaker_name":"Tristan Pelligrino"},{"text":"But I think, you know, now''s a good time to talk through some of the, you know, key to data elements, some certain decisions we need to make sure that''s.","index":82,"end_time":289.48,"speaker_id":0,"start_time":279.639,"speaker_name":"Tristan Pelligrino"},{"text":"That''s where we are.","index":83,"end_time":290.36,"speaker_id":0,"start_time":289.48,"speaker_name":"Tristan Pelligrino"},{"text":"So, Barb, I have your email available.","index":84,"end_time":293.18,"speaker_id":0,"start_time":290.44,"speaker_name":"Tristan Pelligrino"},{"text":"Do you want me to pull that up and kind of.","index":85,"end_time":295.5,"speaker_id":0,"start_time":293.5,"speaker_name":"Tristan Pelligrino"},{"text":"Yeah, that''d be.","index":86,"end_time":296.86,"speaker_id":2,"start_time":295.5,"speaker_name":"bwillans"},{"text":"That''d be great.","index":87,"end_time":298.06,"speaker_id":2,"start_time":297.1,"speaker_name":"bwillans"},{"text":"And we can start at the top.","index":88,"end_time":299.74,"speaker_id":2,"start_time":298.22,"speaker_name":"bwillans"},{"text":"But it''s Vivian''s.","index":89,"end_time":301.18,"speaker_id":2,"start_time":299.74,"speaker_name":"bwillans"},{"text":"I mean, I talk to you guys all the time, and I love it.","index":90,"end_time":304.86,"speaker_id":2,"start_time":302.54,"speaker_name":"bwillans"},{"text":"Don''t get me wrong.","index":91,"end_time":305.66,"speaker_id":2,"start_time":304.86,"speaker_name":"bwillans"},{"text":"But we.","index":92,"end_time":306.5,"speaker_id":2,"start_time":305.66,"speaker_name":"bwillans"},{"text":"We have her for a period of time here, which is really, really important.","index":93,"end_time":312.86,"speaker_id":2,"start_time":306.5,"speaker_name":"bwillans"},{"text":"So I think the top here.","index":94,"end_time":316.02,"speaker_id":2,"start_time":313.26,"speaker_name":"bwillans"},{"text":"I think Vivian is still there.","index":95,"end_time":317.5,"speaker_id":2,"start_time":316.02,"speaker_name":"bwillans"},{"text":"Yep, I''m here.","index":96,"end_time":318.73,"speaker_id":1,"start_time":318.09,"speaker_name":"vivian"},{"text":"I''m just.","index":97,"end_time":319.21,"speaker_id":1,"start_time":318.73,"speaker_name":"vivian"},{"text":"I pulled.","index":98,"end_time":321.01,"speaker_id":1,"start_time":320.41,"speaker_name":"vivian"},{"text":"I. I pulled my notes so that.","index":99,"end_time":322.81,"speaker_id":1,"start_time":321.01,"speaker_name":"vivian"},{"text":"Oh, good.","index":100,"end_time":323.57,"speaker_id":2,"start_time":322.81,"speaker_name":"bwillans"},{"text":"Okay.","index":101,"end_time":324.09,"speaker_id":2,"start_time":323.57,"speaker_name":"bwillans"},{"text":"Yeah, I pulled my notes up.","index":102,"end_time":325.85,"speaker_id":1,"start_time":324.49,"speaker_name":"vivian"},{"text":"Yeah.","index":103,"end_time":326.33,"speaker_id":1,"start_time":325.85,"speaker_name":"vivian"},{"text":"And can you see Tristan''s screen?","index":104,"end_time":328.49,"speaker_id":2,"start_time":326.57,"speaker_name":"bwillans"},{"text":"I''m on my.","index":105,"end_time":332.09,"speaker_id":1,"start_time":331.21,"speaker_name":"vivian"},{"text":"Yes, I can see the screen.","index":106,"end_time":334.25,"speaker_id":1,"start_time":332.73,"speaker_name":"vivian"},{"text":"Perfect.","index":107,"end_time":334.77,"speaker_id":2,"start_time":334.25,"speaker_name":"bwillans"},{"text":"Oh, maybe just if it''s small, maybe just I can read it out or you can.","index":108,"end_time":339.21,"speaker_id":2,"start_time":334.77,"speaker_name":"bwillans"},{"text":"Or I can go through this.","index":109,"end_time":340.13,"speaker_id":2,"start_time":339.21,"speaker_name":"bwillans"},{"text":"But it wasn''t.","index":110,"end_time":340.89,"speaker_id":2,"start_time":340.13,"speaker_name":"bwillans"},{"text":"It wasn''t much.","index":111,"end_time":341.89,"speaker_id":2,"start_time":340.97,"speaker_name":"bwillans"},{"text":"I mean, because we''ve been working so closely together.","index":112,"end_time":344.17,"speaker_id":2,"start_time":341.89,"speaker_name":"bwillans"},{"text":"Yeah.","index":113,"end_time":346.44,"speaker_id":2,"start_time":346.16,"speaker_name":"bwillans"},{"text":"So, Justin, I guess so let me run through mine first and then get to Vivian.","index":114,"end_time":351.68,"speaker_id":2,"start_time":346.44,"speaker_name":"bwillans"},{"text":"So I think they mirrored each other, actually.","index":115,"end_time":353.6,"speaker_id":2,"start_time":351.68,"speaker_name":"bwillans"},{"text":"So my biggest feedback is ensuring that you align to Salesforce and Kyle and we don''t lose the goodness.","index":116,"end_time":360.8,"speaker_id":2,"start_time":353.84,"speaker_name":"bwillans"},{"text":"There was goodness in Marketo.","index":117,"end_time":362.84,"speaker_id":2,"start_time":361.36,"speaker_name":"bwillans"},{"text":"I mean, it was just so big that it was.","index":118,"end_time":365.64,"speaker_id":2,"start_time":362.84,"speaker_name":"bwillans"},{"text":"It was tough to manage.","index":119,"end_time":366.56,"speaker_id":2,"start_time":365.64,"speaker_name":"bwillans"},{"text":"But it doesn''t mean that there wasn''t things that are.","index":120,"end_time":369.92,"speaker_id":2,"start_time":366.56,"speaker_name":"bwillans"},{"text":"That we don''t want to lose, you know, some direction in how we do that.","index":121,"end_time":373.84,"speaker_id":2,"start_time":369.92,"speaker_name":"bwillans"},{"text":"But also, Kyle created a Miro board and aligned it to sales and marketing with Vivian and the sales leads.","index":122,"end_time":381.18,"speaker_id":2,"start_time":374.72,"speaker_name":"bwillans"},{"text":"And Vivian, you dropped off the other day.","index":123,"end_time":383.74,"speaker_id":2,"start_time":381.42,"speaker_name":"bwillans"},{"text":"But I asked Kyle, I said, well, how do I give this to New North?","index":124,"end_time":387.62,"speaker_id":2,"start_time":383.82,"speaker_name":"bwillans"},{"text":"And he said, well, maybe screenshots.","index":125,"end_time":389.26,"speaker_id":2,"start_time":387.62,"speaker_name":"bwillans"},{"text":"I don''t think we can share the mirror board, but maybe we can.","index":126,"end_time":392.78,"speaker_id":2,"start_time":390.22,"speaker_name":"bwillans"},{"text":"So that was the first thing.","index":127,"end_time":394.06,"speaker_id":2,"start_time":392.78,"speaker_name":"bwillans"},{"text":"And I''ll go through this really quickly and then pause.","index":128,"end_time":398.14,"speaker_id":2,"start_time":395.58,"speaker_name":"bwillans"},{"text":"The second thing is Salesforce is the source of truth.","index":129,"end_time":401.18,"speaker_id":2,"start_time":398.46,"speaker_name":"bwillans"},{"text":"But Tristan, I asked Vivian to record request some just to help me out here to engage, get some.","index":130,"end_time":408.1,"speaker_id":2,"start_time":401.66,"speaker_name":"bwillans"},{"text":"What we call engaged list in Marketo because we.","index":131,"end_time":411.7,"speaker_id":2,"start_time":408.1,"speaker_name":"bwillans"},{"text":"We''re.","index":132,"end_time":412.38,"speaker_id":2,"start_time":411.94,"speaker_name":"bwillans"},{"text":"We''re very focused on the MQLs, which is awesome.","index":133,"end_time":414.7,"speaker_id":2,"start_time":412.38,"speaker_name":"bwillans"},{"text":"Like, it''s amazing how well we''re actually doing.","index":134,"end_time":417.06,"speaker_id":2,"start_time":414.7,"speaker_name":"bwillans"},{"text":"Like, but not actually it.","index":135,"end_time":418.58,"speaker_id":2,"start_time":417.06,"speaker_name":"bwillans"},{"text":"Just because it seems one way and the numbers are so big that it''s.","index":136,"end_time":422.7,"speaker_id":2,"start_time":418.58,"speaker_name":"bwillans"},{"text":"It''s really impressive.","index":137,"end_time":424.02,"speaker_id":2,"start_time":422.7,"speaker_name":"bwillans"},{"text":"My view is.","index":138,"end_time":425.62,"speaker_id":2,"start_time":424.9,"speaker_name":"bwillans"},{"text":"Is that we''re missing the top of that funnel.","index":139,"end_time":427.38,"speaker_id":2,"start_time":425.62,"speaker_name":"bwillans"},{"text":"Right.","index":140,"end_time":427.5,"speaker_id":1,"start_time":427.38,"speaker_name":"vivian"},{"text":"Like, we don''t see who''s doing what.","index":141,"end_time":431.31,"speaker_id":2,"start_time":427.5,"speaker_name":"bwillans"},{"text":"This is just.","index":142,"end_time":432.31,"speaker_id":2,"start_time":431.63,"speaker_name":"bwillans"},{"text":"In my view, it could be there maybe I just can''t see it, but the top of the funnel.","index":143,"end_time":436.19,"speaker_id":2,"start_time":432.31,"speaker_name":"bwillans"},{"text":"So I asked her to go in, ask Brazil for some of the list that we.","index":144,"end_time":442.27,"speaker_id":2,"start_time":436.43,"speaker_name":"bwillans"},{"text":"We can just.","index":145,"end_time":443.47,"speaker_id":2,"start_time":442.67,"speaker_name":"bwillans"},{"text":"We don''t want to lose engagement because we track all the engagement.","index":146,"end_time":446.87,"speaker_id":2,"start_time":443.63,"speaker_name":"bwillans"},{"text":"I just don''t know that the engagement, let''s say they did five things.","index":147,"end_time":450.75,"speaker_id":2,"start_time":446.87,"speaker_name":"bwillans"},{"text":"I don''t know that it''s in Salesforce, so just want to make sure we get it from both places.","index":148,"end_time":454.79,"speaker_id":2,"start_time":451.23,"speaker_name":"bwillans"},{"text":"So there''s a couple of examples there.","index":149,"end_time":458.84,"speaker_id":2,"start_time":454.79,"speaker_name":"bwillans"},{"text":"Actually, maybe I''ll pause here because that''s a lot so far.","index":150,"end_time":461.96,"speaker_id":2,"start_time":459,"speaker_name":"bwillans"},{"text":"Yeah.","index":151,"end_time":463.16,"speaker_id":0,"start_time":462.76,"speaker_name":"Tristan Pelligrino"},{"text":"First question I had when I saw your note, Barb, was the magical mirror board.","index":152,"end_time":467.68,"speaker_id":0,"start_time":463.16,"speaker_name":"Tristan Pelligrino"},{"text":"I was wondering how we could get our hands on that somehow.","index":153,"end_time":470.52,"speaker_id":0,"start_time":467.68,"speaker_name":"Tristan Pelligrino"},{"text":"Because I think that''s good.","index":154,"end_time":472.32,"speaker_id":0,"start_time":471.16,"speaker_name":"Tristan Pelligrino"},{"text":"If folks are kind of mapping something out that way, it might be good for us to see that.","index":155,"end_time":477.48,"speaker_id":0,"start_time":472.32,"speaker_name":"Tristan Pelligrino"},{"text":"It''S actually just three screens that we need to send to you.","index":156,"end_time":482.6,"speaker_id":1,"start_time":479.64,"speaker_name":"vivian"},{"text":"So I want to put in context that marrow board.","index":157,"end_time":485.21,"speaker_id":1,"start_time":482.6,"speaker_name":"vivian"},{"text":"It pertains to a very specific thing where the lead.","index":158,"end_time":489.61,"speaker_id":1,"start_time":486.49,"speaker_name":"vivian"},{"text":"The lead source.","index":159,"end_time":491.29,"speaker_id":1,"start_time":490.09,"speaker_name":"vivian"},{"text":"So this is a very, very key report that we''re going to have to run for management in 2026 because this year we had no idea where the leads came from.","index":160,"end_time":501.93,"speaker_id":1,"start_time":492.33,"speaker_name":"vivian"},{"text":"Was it sales generated, was it marketing generated?","index":161,"end_time":505.61,"speaker_id":1,"start_time":501.93,"speaker_name":"vivian"},{"text":"And then from there, what''s the drill down?","index":162,"end_time":508.01,"speaker_id":1,"start_time":505.61,"speaker_name":"vivian"},{"text":"If it was sales generated, was it a referral from Hawk or like a sister company?","index":163,"end_time":514.08,"speaker_id":1,"start_time":508.01,"speaker_name":"vivian"},{"text":"Or did a sales rep go to a network networking event and generate that from the marketing standpoint also, you know, with Barb diversifying the kind of the channels in which we market, we want to be able to measure when it''s marketing generated, where it came from.","index":164,"end_time":530.76,"speaker_id":1,"start_time":514.4,"speaker_name":"vivian"},{"text":"As well.","index":165,"end_time":531.2,"speaker_id":1,"start_time":530.76,"speaker_name":"vivian"},{"text":"And so we came up with a new taxonomy in terms of like how to measure that.","index":166,"end_time":536.72,"speaker_id":1,"start_time":531.44,"speaker_name":"vivian"},{"text":"That taxonomy though is going to be entered by the sales rep and entered by the bdr.","index":167,"end_time":545.71,"speaker_id":1,"start_time":537.39,"speaker_name":"vivian"},{"text":"And so it might not need to connect to HubSpot, but the nomenclature, like the fields that we put in HubSpot probably need to map to some of the nomenclature of this output.","index":168,"end_time":561.31,"speaker_id":1,"start_time":548.43,"speaker_name":"vivian"},{"text":"So that''s a little more specific about that piece of the pie, if that''s helpful.","index":169,"end_time":567.81,"speaker_id":1,"start_time":561.31,"speaker_name":"vivian"},{"text":"Yeah.","index":170,"end_time":569.21,"speaker_id":0,"start_time":568.85,"speaker_name":"Tristan Pelligrino"},{"text":"And so this is when the BDR makes the determination, which now is done on the lead to opportunity conversion.","index":171,"end_time":577.49,"speaker_id":0,"start_time":569.21,"speaker_name":"Tristan Pelligrino"},{"text":"Right.","index":172,"end_time":577.73,"speaker_id":0,"start_time":577.49,"speaker_name":"Tristan Pelligrino"},{"text":"At that point they are electing or describing where the lead came from.","index":173,"end_time":582.77,"speaker_id":0,"start_time":577.73,"speaker_name":"Tristan Pelligrino"},{"text":"Correct.","index":174,"end_time":583.89,"speaker_id":2,"start_time":583.25,"speaker_name":"bwillans"},{"text":"And so.","index":175,"end_time":585.09,"speaker_id":0,"start_time":584.37,"speaker_name":"Tristan Pelligrino"},{"text":"So you''re saying the.","index":176,"end_time":588.93,"speaker_id":0,"start_time":586.61,"speaker_name":"Tristan Pelligrino"},{"text":"That will be what you would like to report on out of Salesforce for management or.","index":177,"end_time":596.86,"speaker_id":0,"start_time":590.94,"speaker_name":"Tristan Pelligrino"},{"text":"Yeah, it''s a key.","index":178,"end_time":598.74,"speaker_id":1,"start_time":597.66,"speaker_name":"vivian"},{"text":"It''s one out of many, but it''s.","index":179,"end_time":601.02,"speaker_id":1,"start_time":598.74,"speaker_name":"vivian"},{"text":"It''s a key management report that they''ve been asking for all year round, which is where did this opportunity come from?","index":180,"end_time":608.7,"speaker_id":1,"start_time":601.02,"speaker_name":"vivian"},{"text":"Yeah, Level one, sales or marketing.","index":181,"end_time":612.02,"speaker_id":1,"start_time":609.1,"speaker_name":"vivian"},{"text":"Level two, more more specifically the channel.","index":182,"end_time":615.26,"speaker_id":1,"start_time":612.02,"speaker_name":"vivian"},{"text":"Yep.","index":183,"end_time":616.31,"speaker_id":0,"start_time":615.91,"speaker_name":"Tristan Pelligrino"},{"text":"And.","index":184,"end_time":616.95,"speaker_id":0,"start_time":616.55,"speaker_name":"Tristan Pelligrino"},{"text":"And that is.","index":185,"end_time":617.75,"speaker_id":0,"start_time":616.95,"speaker_name":"Tristan Pelligrino"},{"text":"And that''s one of Our key questions, like when we think about.","index":186,"end_time":620.63,"speaker_id":0,"start_time":617.75,"speaker_name":"Tristan Pelligrino"},{"text":"And I don''t want to get too into the weeds on this, but it''s something that we need to figure out is, is the objects that we''re mapping, so contacts to.","index":187,"end_time":632.07,"speaker_id":0,"start_time":621.11,"speaker_name":"Tristan Pelligrino"},{"text":"From HubSpot to Salesforce and then the opportunity record that can also Sync back to HubSpot.","index":188,"end_time":638.47,"speaker_id":0,"start_time":632.47,"speaker_name":"Tristan Pelligrino"},{"text":"Obviously there we can store Source at those two different objects.","index":189,"end_time":643.76,"speaker_id":0,"start_time":638.47,"speaker_name":"Tristan Pelligrino"},{"text":"So like the contact and this might even be a question is what would the answer be in this situation?","index":190,"end_time":649.76,"speaker_id":0,"start_time":643.76,"speaker_name":"Tristan Pelligrino"},{"text":"So let''s say a contact comes from direct search.","index":191,"end_time":655.28,"speaker_id":0,"start_time":649.76,"speaker_name":"Tristan Pelligrino"},{"text":"Like they.","index":192,"end_time":656.04,"speaker_id":0,"start_time":655.52,"speaker_name":"Tristan Pelligrino"},{"text":"Or.","index":193,"end_time":656.36,"speaker_id":0,"start_time":656.04,"speaker_name":"Tristan Pelligrino"},{"text":"And they downloaded a PDF or something.","index":194,"end_time":659.16,"speaker_id":0,"start_time":656.36,"speaker_name":"Tristan Pelligrino"},{"text":"Right.","index":195,"end_time":659.48,"speaker_id":0,"start_time":659.16,"speaker_name":"Tristan Pelligrino"},{"text":"So they filled out a form.","index":196,"end_time":660.56,"speaker_id":0,"start_time":659.48,"speaker_name":"Tristan Pelligrino"},{"text":"The.","index":197,"end_time":662.4,"speaker_id":2,"start_time":662,"speaker_name":"bwillans"},{"text":"The original source in HubSpot will direct you towards either direct or organic.","index":198,"end_time":670.17,"speaker_id":0,"start_time":662.56,"speaker_name":"Tristan Pelligrino"},{"text":"Right.","index":199,"end_time":671.69,"speaker_id":2,"start_time":671.29,"speaker_name":"bwillans"},{"text":"And so that can flow through to Salesforce on the contact record.","index":200,"end_time":675.85,"speaker_id":0,"start_time":671.77,"speaker_name":"Tristan Pelligrino"},{"text":"We can set up that sync and then you have the opportunity record that''s created separately.","index":201,"end_time":682.09,"speaker_id":0,"start_time":675.85,"speaker_name":"Tristan Pelligrino"},{"text":"You can have a source attached to the opportunity record as well.","index":202,"end_time":685.53,"speaker_id":0,"start_time":682.09,"speaker_name":"Tristan Pelligrino"},{"text":"Because in.","index":203,"end_time":687.09,"speaker_id":0,"start_time":685.93,"speaker_name":"Tristan Pelligrino"},{"text":"The reason we sometimes do this is let''s say you have two contacts at the company.","index":204,"end_time":690.81,"speaker_id":0,"start_time":687.09,"speaker_name":"Tristan Pelligrino"},{"text":"One came through organic, the other one was a trade show manual upload.","index":205,"end_time":696.76,"speaker_id":0,"start_time":691.21,"speaker_name":"Tristan Pelligrino"},{"text":"Right?","index":206,"end_time":697.24,"speaker_id":0,"start_time":696.84,"speaker_name":"Tristan Pelligrino"},{"text":"What.","index":207,"end_time":698.24,"speaker_id":0,"start_time":697.88,"speaker_name":"Tristan Pelligrino"},{"text":"What should the opportunity source be in that situation?","index":208,"end_time":702.16,"speaker_id":0,"start_time":698.24,"speaker_name":"Tristan Pelligrino"},{"text":"If one is offline trade show and another one is organic, what would the opportunity state?","index":209,"end_time":708.68,"speaker_id":0,"start_time":702.16,"speaker_name":"Tristan Pelligrino"},{"text":"And there, there might not.","index":210,"end_time":715.12,"speaker_id":0,"start_time":713.88,"speaker_name":"Tristan Pelligrino"},{"text":"There''s not even like a right or wrong, but it''s like what do we.","index":211,"end_time":717.68,"speaker_id":0,"start_time":715.12,"speaker_name":"Tristan Pelligrino"},{"text":"So sure.","index":212,"end_time":718.76,"speaker_id":1,"start_time":717.68,"speaker_name":"vivian"},{"text":"So my hope is.","index":213,"end_time":721.13,"speaker_id":1,"start_time":720.25,"speaker_name":"vivian"},{"text":"And Barb, this is a good discussion and you may have a different point of view is.","index":214,"end_time":724.77,"speaker_id":1,"start_time":721.13,"speaker_name":"vivian"},{"text":"I just.","index":215,"end_time":725.21,"speaker_id":1,"start_time":724.77,"speaker_name":"vivian"},{"text":"All I care about is that the taxonomy that we use in Salesforce and the taxonomy we use in HubSpot is like there''s a relationship.","index":216,"end_time":733.05,"speaker_id":1,"start_time":725.21,"speaker_name":"vivian"},{"text":"Like they''re.","index":217,"end_time":733.53,"speaker_id":1,"start_time":733.05,"speaker_name":"vivian"},{"text":"They''re equal.","index":218,"end_time":734.25,"speaker_id":1,"start_time":733.53,"speaker_name":"vivian"},{"text":"We''re not creating different like two sets of nomenclature.","index":219,"end_time":737.25,"speaker_id":1,"start_time":734.25,"speaker_name":"vivian"},{"text":"Like in HubSpot, the fields are a little different than the.","index":220,"end_time":739.97,"speaker_id":1,"start_time":737.25,"speaker_name":"vivian"},{"text":"The ones in Salesforce.","index":221,"end_time":741.09,"speaker_id":1,"start_time":739.97,"speaker_name":"vivian"},{"text":"So like, you know, I, I want some matching, you know, if that makes sense.","index":222,"end_time":744.73,"speaker_id":1,"start_time":741.09,"speaker_name":"vivian"},{"text":"Yeah, yeah.","index":223,"end_time":746.23,"speaker_id":0,"start_time":745.23,"speaker_name":"Tristan Pelligrino"},{"text":"And that''s.","index":224,"end_time":746.83,"speaker_id":0,"start_time":746.23,"speaker_name":"Tristan Pelligrino"},{"text":"And I think there''s two.","index":225,"end_time":748.11,"speaker_id":0,"start_time":746.99,"speaker_name":"Tristan Pelligrino"},{"text":"Two ways to match it.","index":226,"end_time":749.51,"speaker_id":0,"start_time":748.35,"speaker_name":"Tristan Pelligrino"},{"text":"It''s like at the object level and we can make sure there''s a common definition there.","index":227,"end_time":754.91,"speaker_id":0,"start_time":749.51,"speaker_name":"Tristan Pelligrino"},{"text":"And then I think the.","index":228,"end_time":755.71,"speaker_id":0,"start_time":754.91,"speaker_name":"Tristan Pelligrino"},{"text":"The other big question is because right now at the opportunity level, that''s manual.","index":229,"end_time":761.87,"speaker_id":0,"start_time":755.71,"speaker_name":"Tristan Pelligrino"},{"text":"It''s like a decision that''s made by the BDR.","index":230,"end_time":765.47,"speaker_id":0,"start_time":761.87,"speaker_name":"Tristan Pelligrino"},{"text":"Yeah, you got it.","index":231,"end_time":766.67,"speaker_id":1,"start_time":765.63,"speaker_name":"vivian"},{"text":"You totally got it.","index":232,"end_time":768.11,"speaker_id":1,"start_time":766.67,"speaker_name":"vivian"},{"text":"100 got it.","index":233,"end_time":770.11,"speaker_id":1,"start_time":768.67,"speaker_name":"vivian"},{"text":"And that would.","index":234,"end_time":772.27,"speaker_id":0,"start_time":771.47,"speaker_name":"Tristan Pelligrino"},{"text":"So what we would do in that case, Vivian, is that would be a field on the opportunity level.","index":235,"end_time":779.2,"speaker_id":0,"start_time":773.04,"speaker_name":"Tristan Pelligrino"},{"text":"We could call it an opportunity source or deal source, which you know, would map to Salesforce.","index":236,"end_time":785.2,"speaker_id":0,"start_time":779.52,"speaker_name":"Tristan Pelligrino"},{"text":"And then the contact also could have A source.","index":237,"end_time":787.6,"speaker_id":0,"start_time":785.2,"speaker_name":"Tristan Pelligrino"},{"text":"Those could be two separate fields just lined up.","index":238,"end_time":789.76,"speaker_id":0,"start_time":787.6,"speaker_name":"Tristan Pelligrino"},{"text":"So hopefully there is something that goes from HubSpot to Salesforce that.","index":239,"end_time":794.72,"speaker_id":1,"start_time":790.32,"speaker_name":"vivian"},{"text":"So that Blake, when he looks at it, he maps it correctly.","index":240,"end_time":797.64,"speaker_id":1,"start_time":794.8,"speaker_name":"vivian"},{"text":"Do you know it''s like a little bit like the.","index":241,"end_time":799.52,"speaker_id":1,"start_time":797.64,"speaker_name":"vivian"},{"text":"Like there''s a continuum.","index":242,"end_time":801.08,"speaker_id":1,"start_time":800.04,"speaker_name":"vivian"},{"text":"It''s like, oh, okay, this came from social media.","index":243,"end_time":806.2,"speaker_id":1,"start_time":801.08,"speaker_name":"vivian"},{"text":"Okay, I''ll flag it.","index":244,"end_time":807.28,"speaker_id":1,"start_time":806.28,"speaker_name":"vivian"},{"text":"Social media.","index":245,"end_time":807.8,"speaker_id":1,"start_time":807.28,"speaker_name":"vivian"},{"text":"Like he''s prompted on how to do it so that he''s not guessing, he''s not looking at some campaign code and being like, I don''t know what that is.","index":246,"end_time":815.72,"speaker_id":1,"start_time":807.8,"speaker_name":"vivian"},{"text":"Other.","index":247,"end_time":816.36,"speaker_id":1,"start_time":815.96,"speaker_name":"vivian"},{"text":"Right, yeah.","index":248,"end_time":819.08,"speaker_id":0,"start_time":817.24,"speaker_name":"Tristan Pelligrino"},{"text":"And there''s a way, I mean, we could just automate that, which is one of the workflows that we need to talk through.","index":249,"end_time":826.68,"speaker_id":0,"start_time":819.32,"speaker_name":"Tristan Pelligrino"},{"text":"Even better.","index":250,"end_time":827.88,"speaker_id":1,"start_time":827.24,"speaker_name":"vivian"},{"text":"Yeah.","index":251,"end_time":828.76,"speaker_id":0,"start_time":828.36,"speaker_name":"Tristan Pelligrino"},{"text":"Because on the Salesforce side right now there''s some custom code that does like the conversion right.","index":252,"end_time":834.55,"speaker_id":0,"start_time":828.76,"speaker_name":"Tristan Pelligrino"},{"text":"From the lead to Opportunity.","index":253,"end_time":836.43,"speaker_id":0,"start_time":834.55,"speaker_name":"Tristan Pelligrino"},{"text":"We could map a field that we have already in Salesforce that maps from HubSpot and it says whatever we determine those list of values are.","index":254,"end_time":848.15,"speaker_id":0,"start_time":837.39,"speaker_name":"Tristan Pelligrino"},{"text":"It could just copy that to the opportunity source if we like.","index":255,"end_time":852.03,"speaker_id":0,"start_time":848.15,"speaker_name":"Tristan Pelligrino"},{"text":"So related to that, Tristan, the document that you created is awesome.","index":256,"end_time":859.38,"speaker_id":1,"start_time":852.43,"speaker_name":"vivian"},{"text":"We just need to make sure it gets vetted with Maria, Kyle, because we''re about to change what we call our standard of work, our process.","index":257,"end_time":872.02,"speaker_id":1,"start_time":859.78,"speaker_name":"vivian"},{"text":"They just need to be informed how these workflows are about to change.","index":258,"end_time":876.74,"speaker_id":1,"start_time":872.58,"speaker_name":"vivian"},{"text":"So I would love for them to just be another lens.","index":259,"end_time":881.7,"speaker_id":1,"start_time":877.78,"speaker_name":"vivian"},{"text":"I also think it doesn''t hurt to include the BDR because the BDR is the end recipient of the marketing lead.","index":260,"end_time":892.36,"speaker_id":1,"start_time":881.94,"speaker_name":"vivian"},{"text":"And so Blake needs to have a little bit of a heads up about how things are about to change in his world as well.","index":261,"end_time":898.2,"speaker_id":1,"start_time":892.76,"speaker_name":"vivian"},{"text":"And we''re changing it for the better.","index":262,"end_time":899.88,"speaker_id":1,"start_time":898.28,"speaker_name":"vivian"},{"text":"So I don''t see there being any issue, but it''s the last sanity check as well as buy in from the people that need to be aware of the change.","index":263,"end_time":909,"speaker_id":1,"start_time":899.88,"speaker_name":"vivian"},{"text":"Yeah, yeah.","index":264,"end_time":911.09,"speaker_id":0,"start_time":910.21,"speaker_name":"Tristan Pelligrino"},{"text":"And the other thing with Kyle and it''s Maria, right?","index":265,"end_time":914.85,"speaker_id":0,"start_time":911.09,"speaker_name":"Tristan Pelligrino"},{"text":"Yeah, Maria.","index":266,"end_time":915.89,"speaker_id":1,"start_time":915.09,"speaker_name":"vivian"},{"text":"Yeah.","index":267,"end_time":916.57,"speaker_id":0,"start_time":916.21,"speaker_name":"Tristan Pelligrino"},{"text":"With Kyle and Maria there.","index":268,"end_time":917.81,"speaker_id":0,"start_time":916.57,"speaker_name":"Tristan Pelligrino"},{"text":"There is some work in Salesforce we would have to change too.","index":269,"end_time":920.89,"speaker_id":0,"start_time":917.81,"speaker_name":"Tristan Pelligrino"},{"text":"So we would have to work with them because right now they have that conversion.","index":270,"end_time":924.97,"speaker_id":0,"start_time":920.89,"speaker_name":"Tristan Pelligrino"},{"text":"Right.","index":271,"end_time":925.21,"speaker_id":0,"start_time":924.97,"speaker_name":"Tristan Pelligrino"},{"text":"That''s built.","index":272,"end_time":925.809,"speaker_id":0,"start_time":925.21,"speaker_name":"Tristan Pelligrino"},{"text":"There is some custom code that does that.","index":273,"end_time":927.49,"speaker_id":0,"start_time":925.809,"speaker_name":"Tristan Pelligrino"},{"text":"So we have to work with them and say, hey, here''s the field that you would pull from now and that would be a modification on that side too.","index":274,"end_time":936.01,"speaker_id":0,"start_time":927.49,"speaker_name":"Tristan Pelligrino"},{"text":"So.","index":275,"end_time":936.37,"speaker_id":0,"start_time":936.01,"speaker_name":"Tristan Pelligrino"},{"text":"Yeah.","index":276,"end_time":937.29,"speaker_id":2,"start_time":936.97,"speaker_name":"bwillans"},{"text":"Awesome.","index":277,"end_time":940.13,"speaker_id":2,"start_time":939.53,"speaker_name":"bwillans"},{"text":"So a couple of things.","index":278,"end_time":941.21,"speaker_id":2,"start_time":940.13,"speaker_name":"bwillans"},{"text":"One, I mean, Kyla, Maria seemed totally open to that as long as it made sense for all of us.","index":279,"end_time":947.93,"speaker_id":2,"start_time":942.25,"speaker_name":"bwillans"},{"text":"So we would have to socialize that as well.","index":280,"end_time":950.01,"speaker_id":2,"start_time":947.93,"speaker_name":"bwillans"},{"text":"But maybe I think I Tend to get ahead of myself and go straight down to tactical.","index":281,"end_time":954.65,"speaker_id":2,"start_time":950.17,"speaker_name":"bwillans"},{"text":"So how about Tristan just kind of go way down into my email.","index":282,"end_time":958.97,"speaker_id":2,"start_time":954.73,"speaker_name":"bwillans"},{"text":"I think this is going to make more sense while we have Vivian here and she asked some very good questions and just said when do we involve, you know, Blake and Kyle?","index":283,"end_time":971.11,"speaker_id":2,"start_time":958.97,"speaker_name":"bwillans"},{"text":"So my comments are below.","index":284,"end_time":972.55,"speaker_id":2,"start_time":971.11,"speaker_name":"bwillans"},{"text":"But Blake is our bdr.","index":285,"end_time":974.67,"speaker_id":2,"start_time":972.55,"speaker_name":"bwillans"},{"text":"He''s incredibly important to this process.","index":286,"end_time":976.87,"speaker_id":2,"start_time":974.67,"speaker_name":"bwillans"},{"text":"We are hiring another one, but it''s just kind of waiting to see when he should be aligned and brought into these workflows.","index":287,"end_time":984.95,"speaker_id":2,"start_time":976.87,"speaker_name":"bwillans"},{"text":"You''ve met Kyle, we talked about that mapping process in Miro.","index":288,"end_time":989.03,"speaker_id":2,"start_time":984.95,"speaker_name":"bwillans"},{"text":"I can just do a couple of screenshots.","index":289,"end_time":991.67,"speaker_id":2,"start_time":989.95,"speaker_name":"bwillans"},{"text":"But I did speak with him and he said yeah, Tristan should be aware of this and we''ll decide that and then we''ll talk about the, the database work.","index":290,"end_time":1000.23,"speaker_id":2,"start_time":991.67,"speaker_name":"bwillans"},{"text":"But just let''s, let''s go through Vivian''s questions and make sure that they''re, they''re addressed.","index":291,"end_time":1006.83,"speaker_id":2,"start_time":1000.23,"speaker_name":"bwillans"},{"text":"Yeah.","index":292,"end_time":1008.19,"speaker_id":0,"start_time":1007.79,"speaker_name":"Tristan Pelligrino"},{"text":"Can you see these, Vivian?","index":293,"end_time":1009.23,"speaker_id":0,"start_time":1008.19,"speaker_name":"Tristan Pelligrino"},{"text":"Are they.","index":294,"end_time":1009.71,"speaker_id":0,"start_time":1009.23,"speaker_name":"Tristan Pelligrino"},{"text":"I can actually.","index":295,"end_time":1010.63,"speaker_id":1,"start_time":1009.87,"speaker_name":"vivian"},{"text":"Okay, yeah, perfect.","index":296,"end_time":1011.55,"speaker_id":0,"start_time":1010.63,"speaker_name":"Tristan Pelligrino"},{"text":"I can blow up a little bit more.","index":297,"end_time":1013.23,"speaker_id":0,"start_time":1011.79,"speaker_name":"Tristan Pelligrino"},{"text":"Thank you for checking.","index":298,"end_time":1014.43,"speaker_id":1,"start_time":1013.55,"speaker_name":"vivian"},{"text":"Yeah, you want to go through?","index":299,"end_time":1015.55,"speaker_id":0,"start_time":1014.59,"speaker_name":"Tristan Pelligrino"},{"text":"So yeah, the, the Blake and Kyle''s the first one here.","index":300,"end_time":1017.95,"speaker_id":0,"start_time":1015.55,"speaker_name":"Tristan Pelligrino"},{"text":"Is there, is there a point in time where like, should we present what we have or like how would you feel would be the best route to take there?","index":301,"end_time":1037.17,"speaker_id":0,"start_time":1028.77,"speaker_name":"Tristan Pelligrino"},{"text":"I mean I, the documents are so well written.","index":302,"end_time":1042.29,"speaker_id":1,"start_time":1039.65,"speaker_name":"vivian"},{"text":"I would send the HubSpot implementation plan to them, give them a deadline and then maybe have a follow up meeting just like we''re having now and being like what''s your comment and feedback like?","index":303,"end_time":1053.899,"speaker_id":1,"start_time":1042.37,"speaker_name":"vivian"},{"text":"I love, yeah, I love how we did it for us.","index":304,"end_time":1056.579,"speaker_id":1,"start_time":1053.899,"speaker_name":"vivian"},{"text":"So I would do it exactly the same.","index":305,"end_time":1058.419,"speaker_id":1,"start_time":1056.659,"speaker_name":"vivian"},{"text":"Yeah, yeah, that works too because I know Kyle Marie are pretty detail oriented so they''ll be able to check some of the fields and probably have a good discussion from that standpoint.","index":306,"end_time":1071.979,"speaker_id":0,"start_time":1060.819,"speaker_name":"Tristan Pelligrino"},{"text":"Okay.","index":307,"end_time":1072.499,"speaker_id":0,"start_time":1071.979,"speaker_name":"Tristan Pelligrino"},{"text":"And Barb, is that something that you would facilitate?","index":308,"end_time":1075.779,"speaker_id":0,"start_time":1072.979,"speaker_name":"Tristan Pelligrino"},{"text":"What do you think the best way for, for that would be?","index":309,"end_time":1078.22,"speaker_id":0,"start_time":1075.779,"speaker_name":"Tristan Pelligrino"},{"text":"Yeah, if you could send over your schedule again, I''ll, I''ll take a look at the stakeholders for sure.","index":310,"end_time":1083.26,"speaker_id":2,"start_time":1078.86,"speaker_name":"bwillans"},{"text":"Okay, sounds good there.","index":311,"end_time":1085.58,"speaker_id":0,"start_time":1083.34,"speaker_name":"Tristan Pelligrino"},{"text":"And I think we would make some adjustments based on your feedback.","index":312,"end_time":1089.06,"speaker_id":0,"start_time":1085.82,"speaker_name":"Tristan Pelligrino"},{"text":"Perhaps there are a couple things that we should tweak before that goes to, to Kyle and Maria or what do you think?","index":313,"end_time":1095.1,"speaker_id":0,"start_time":1089.06,"speaker_name":"Tristan Pelligrino"},{"text":"Not sure about the tweaking.","index":314,"end_time":1103.1,"speaker_id":2,"start_time":1101.98,"speaker_name":"bwillans"},{"text":"I, I mean we need to align.","index":315,"end_time":1105.42,"speaker_id":2,"start_time":1103.1,"speaker_name":"bwillans"},{"text":"So I guess my question is what would New north need ahead of that conversation knowing that this, this massive undertaking and lead definitions is underway and, and Kyle knows that you don''t have mirror access.","index":316,"end_time":1122.73,"speaker_id":2,"start_time":1106.25,"speaker_name":"bwillans"},{"text":"Like what, what would you need before that conversation.","index":317,"end_time":1125.21,"speaker_id":2,"start_time":1122.73,"speaker_name":"bwillans"},{"text":"Yeah, I think that''s, that''s really one of the, the big questions.","index":318,"end_time":1131.09,"speaker_id":0,"start_time":1125.93,"speaker_name":"Tristan Pelligrino"},{"text":"Like Guille, Colin and I have.","index":319,"end_time":1133.09,"speaker_id":0,"start_time":1131.09,"speaker_name":"Tristan Pelligrino"},{"text":"It''s.","index":320,"end_time":1133.53,"speaker_id":0,"start_time":1133.09,"speaker_name":"Tristan Pelligrino"},{"text":"It''s not even on the technical side necessarily.","index":321,"end_time":1137.34,"speaker_id":0,"start_time":1134.22,"speaker_name":"Tristan Pelligrino"},{"text":"It''s like functionally what are we calling these different called life cycle stages or you know, from lead to MQL to.","index":322,"end_time":1147.26,"speaker_id":0,"start_time":1137.34,"speaker_name":"Tristan Pelligrino"},{"text":"Because I even think like a sales qualified lead would be helpful to introduce because effectively that''s what we''re doing.","index":323,"end_time":1153.3,"speaker_id":0,"start_time":1147.5,"speaker_name":"Tristan Pelligrino"},{"text":"And so I think we need to understand probably business process and make sure we''re good there.","index":324,"end_time":1158.86,"speaker_id":0,"start_time":1153.3,"speaker_name":"Tristan Pelligrino"},{"text":"And then there might be some things we need to adjust on the configuration side.","index":325,"end_time":1164.12,"speaker_id":0,"start_time":1158.86,"speaker_name":"Tristan Pelligrino"},{"text":"Right.","index":326,"end_time":1164.6,"speaker_id":0,"start_time":1164.2,"speaker_name":"Tristan Pelligrino"},{"text":"And some decisions to make there.","index":327,"end_time":1166.28,"speaker_id":0,"start_time":1164.6,"speaker_name":"Tristan Pelligrino"},{"text":"So that''s probably where I would come at it with is like, do we have kind of our updated common definitions of what these things are and what happens to move them along each stage.","index":328,"end_time":1177.88,"speaker_id":0,"start_time":1166.36,"speaker_name":"Tristan Pelligrino"},{"text":"And then based on that we might have some adjustments to make with, with how we configure HubSpot.","index":329,"end_time":1184.12,"speaker_id":0,"start_time":1178.44,"speaker_name":"Tristan Pelligrino"},{"text":"Okay, well, Vivian Blake, our BDR and myself and Jess, Vivian''s our VP.","index":330,"end_time":1193.73,"speaker_id":2,"start_time":1185.25,"speaker_name":"bwillans"},{"text":"We met on the life cycle stage very briefly this week.","index":331,"end_time":1197.49,"speaker_id":2,"start_time":1194.05,"speaker_name":"bwillans"},{"text":"So we did make some determinations, but I have not connected with Kyle, Kyle and Vivian on those.","index":332,"end_time":1204.85,"speaker_id":2,"start_time":1197.81,"speaker_name":"bwillans"},{"text":"So for instance, you know, what, what does that mean?","index":333,"end_time":1208.53,"speaker_id":2,"start_time":1205.25,"speaker_name":"bwillans"},{"text":"Like what are the definitions for each of these?","index":334,"end_time":1210.37,"speaker_id":2,"start_time":1208.53,"speaker_name":"bwillans"},{"text":"And for instance, what do we need and not need?","index":335,"end_time":1213.17,"speaker_id":2,"start_time":1210.37,"speaker_name":"bwillans"},{"text":"So I can share that with you.","index":336,"end_time":1214.93,"speaker_id":2,"start_time":1213.65,"speaker_name":"bwillans"},{"text":"I just haven''t got there yet, but I can share that, that with you and then we can decide from there if he needs to be on that call.","index":337,"end_time":1221.08,"speaker_id":2,"start_time":1214.93,"speaker_name":"bwillans"},{"text":"Yeah, yeah, that would work for us.","index":338,"end_time":1223.72,"speaker_id":0,"start_time":1221.8,"speaker_name":"Tristan Pelligrino"},{"text":"That would be the main things we would need.","index":339,"end_time":1226.88,"speaker_id":0,"start_time":1225.08,"speaker_name":"Tristan Pelligrino"},{"text":"And then, yeah, like you said, we''re just aligning like, hey, here''s an approach, you know, what, what adjustments would be required in Salesforce or like what, you know, red flags do you see?","index":340,"end_time":1237.68,"speaker_id":0,"start_time":1226.88,"speaker_name":"Tristan Pelligrino"},{"text":"Like, is there something that we''re missing?","index":341,"end_time":1239.28,"speaker_id":0,"start_time":1237.68,"speaker_name":"Tristan Pelligrino"},{"text":"Because that''s always a key thing too is like, hey, here''s a, here''s an approach we can take.","index":342,"end_time":1243.48,"speaker_id":0,"start_time":1239.28,"speaker_name":"Tristan Pelligrino"},{"text":"But have we forgot something, you know, or something going to fall out with this type of implementation or even data mapping?","index":343,"end_time":1250.28,"speaker_id":0,"start_time":1243.64,"speaker_name":"Tristan Pelligrino"},{"text":"So yeah, sure.","index":344,"end_time":1251.32,"speaker_id":2,"start_time":1250.36,"speaker_name":"bwillans"},{"text":"For me, when I looked at the document, there was like nothing.","index":345,"end_time":1254.68,"speaker_id":1,"start_time":1251.8,"speaker_name":"vivian"},{"text":"I felt like I needed to change the lens that I looked at.","index":346,"end_time":1258.52,"speaker_id":1,"start_time":1255.16,"speaker_name":"vivian"},{"text":"It was like, who do we need to involve to get, you know, as well?","index":347,"end_time":1261.4,"speaker_id":1,"start_time":1258.52,"speaker_name":"vivian"},{"text":"And like, how do we communicate this change management?","index":348,"end_time":1264.04,"speaker_id":1,"start_time":1261.72,"speaker_name":"vivian"},{"text":"And then the third thing was probably like, ooh, we may need to inventory some next level of detail.","index":349,"end_time":1270.65,"speaker_id":1,"start_time":1264.6,"speaker_name":"vivian"},{"text":"That''s it.","index":350,"end_time":1272.09,"speaker_id":1,"start_time":1271.45,"speaker_name":"vivian"},{"text":"But the document itself was solid.","index":351,"end_time":1274.05,"speaker_id":1,"start_time":1272.17,"speaker_name":"vivian"},{"text":"Like I think certainly from my standpoint, no, no edits required.","index":352,"end_time":1279.49,"speaker_id":1,"start_time":1274.05,"speaker_name":"vivian"},{"text":"Just buy in and next level of detail from a feedback from.","index":353,"end_time":1284.21,"speaker_id":1,"start_time":1279.49,"speaker_name":"vivian"},{"text":"From that stakeholder group.","index":354,"end_time":1285.45,"speaker_id":1,"start_time":1284.21,"speaker_name":"vivian"},{"text":"Yeah, and I think that''s really your.","index":355,"end_time":1288.81,"speaker_id":0,"start_time":1286.65,"speaker_name":"Tristan Pelligrino"},{"text":"Your third comment here, Vivian.","index":356,"end_time":1290.73,"speaker_id":0,"start_time":1288.81,"speaker_name":"Tristan Pelligrino"},{"text":"Which perfect segue is that?","index":357,"end_time":1292.73,"speaker_id":0,"start_time":1290.73,"speaker_name":"Tristan Pelligrino"},{"text":"That detail, that''s when we get to the individual records.","index":358,"end_time":1295.45,"speaker_id":0,"start_time":1292.73,"speaker_name":"Tristan Pelligrino"},{"text":"And yeah, like we had noted, because we were thinking the.","index":359,"end_time":1301.23,"speaker_id":0,"start_time":1297.23,"speaker_name":"Tristan Pelligrino"},{"text":"The approach to take Marketo, Salesforce and then HubSpot''s, we got three systems and we''re thinking we go from Salesforce.","index":360,"end_time":1308.43,"speaker_id":0,"start_time":1301.23,"speaker_name":"Tristan Pelligrino"},{"text":"That''s where we''re starting.","index":361,"end_time":1309.55,"speaker_id":0,"start_time":1308.43,"speaker_name":"Tristan Pelligrino"},{"text":"And I think that the one question here is, are we cleaning up Salesforce and enriching that data and then effectively turning on the HubSpot sync?","index":362,"end_time":1320.11,"speaker_id":0,"start_time":1309.95,"speaker_name":"Tristan Pelligrino"},{"text":"So that first time that it syncs, we have the data mapping set up and then, you know, we''re pulling all that data from Salesforce the first time, or are we cleaning up that data somewhere else independent, and then we''re importing it into HubSpot and then it syncs from there.","index":363,"end_time":1339.74,"speaker_id":0,"start_time":1320.43,"speaker_name":"Tristan Pelligrino"},{"text":"So that was like another key decision we wanted to cover.","index":364,"end_time":1342.86,"speaker_id":0,"start_time":1339.82,"speaker_name":"Tristan Pelligrino"},{"text":"Looking towards your guidance on what the best approach would be, given your experience.","index":365,"end_time":1356.07,"speaker_id":1,"start_time":1349.99,"speaker_name":"vivian"},{"text":"On it, I believe.","index":366,"end_time":1358.55,"speaker_id":2,"start_time":1356.23,"speaker_name":"bwillans"},{"text":"And Guille and I were talking about this yesterday or today.","index":367,"end_time":1362.27,"speaker_id":0,"start_time":1358.63,"speaker_name":"Tristan Pelligrino"},{"text":"I can''t remember.","index":368,"end_time":1362.95,"speaker_id":0,"start_time":1362.27,"speaker_name":"Tristan Pelligrino"},{"text":"Gay days Run Run together.","index":369,"end_time":1364.83,"speaker_id":0,"start_time":1362.95,"speaker_name":"Tristan Pelligrino"},{"text":"But it would be looking at how do we clean up Salesforce and the work we do there and then turning on one sync and letting that just flow through and then doing a data check after that and saying, all right, is HubSpot and Salesforce in the same?","index":370,"end_time":1382.56,"speaker_id":0,"start_time":1364.83,"speaker_name":"Tristan Pelligrino"},{"text":"You know, let''s do spot checks and there''ll be a whole, you know, data validation point there.","index":371,"end_time":1388.72,"speaker_id":0,"start_time":1382.72,"speaker_name":"Tristan Pelligrino"},{"text":"But when we do that, you know, then what.","index":372,"end_time":1393,"speaker_id":0,"start_time":1389.2,"speaker_name":"Tristan Pelligrino"},{"text":"What happens to Marketo at that point?","index":373,"end_time":1395.2,"speaker_id":0,"start_time":1393,"speaker_name":"Tristan Pelligrino"},{"text":"Do we have a clean cutoff?","index":374,"end_time":1397.12,"speaker_id":0,"start_time":1395.2,"speaker_name":"Tristan Pelligrino"},{"text":"You know, that.","index":375,"end_time":1397.88,"speaker_id":0,"start_time":1397.28,"speaker_name":"Tristan Pelligrino"},{"text":"That timing we need to figure out.","index":376,"end_time":1399.6,"speaker_id":0,"start_time":1397.88,"speaker_name":"Tristan Pelligrino"},{"text":"The nice thing though is if we do sync with Salesforce, we can always roll it back in HubSpot.","index":377,"end_time":1406.83,"speaker_id":0,"start_time":1400.24,"speaker_name":"Tristan Pelligrino"},{"text":"We can effectively delete everything and start over as well.","index":378,"end_time":1411.39,"speaker_id":0,"start_time":1406.83,"speaker_name":"Tristan Pelligrino"},{"text":"Because we''re, you know, we would have Marketo still running.","index":379,"end_time":1414.63,"speaker_id":0,"start_time":1411.39,"speaker_name":"Tristan Pelligrino"},{"text":"So.","index":380,"end_time":1415.79,"speaker_id":0,"start_time":1415.51,"speaker_name":"Tristan Pelligrino"},{"text":"Yeah, so let me get a little prescriptive on the database things.","index":381,"end_time":1420.87,"speaker_id":1,"start_time":1415.79,"speaker_name":"vivian"},{"text":"So Barb and I had a really good session two days ago or yesterday where we kind of were like, okay, how do we get to that 17,000 database?","index":382,"end_time":1431.52,"speaker_id":1,"start_time":1421.03,"speaker_name":"vivian"},{"text":"Like, we''ve got obviously a superset right now that''s beyond 17.","index":383,"end_time":1436.08,"speaker_id":1,"start_time":1431.52,"speaker_name":"vivian"},{"text":"So we now need to like, curate and create a criterion on what goes into that 17 that gets, you know, marketing on.","index":384,"end_time":1444.6,"speaker_id":1,"start_time":1436.16,"speaker_name":"vivian"},{"text":"And so we started with the different customer segments that we service.","index":385,"end_time":1449.28,"speaker_id":1,"start_time":1444.6,"speaker_name":"vivian"},{"text":"You know, some of them were like wims existing customers, WIMS Net new, you know, and then and then industrial customers.","index":386,"end_time":1458,"speaker_id":1,"start_time":1449.92,"speaker_name":"vivian"},{"text":"And so there were like a couple of key segments that were really important to us.","index":387,"end_time":1462.06,"speaker_id":1,"start_time":1458,"speaker_name":"vivian"},{"text":"And so do we work with Kyle and Maria to be like, hey, Kyle, Maria, here are the segments that are really important to us that we and that, like.","index":388,"end_time":1473.42,"speaker_id":1,"start_time":1462.54,"speaker_name":"vivian"},{"text":"And then I guess my question is like, like, how do we then create a modifier or identifier so you know what to pull from Salesforce into Hubs, you know what I mean?","index":389,"end_time":1482.58,"speaker_id":1,"start_time":1473.42,"speaker_name":"vivian"},{"text":"Like, how do we go about doing this exercise of process of elimination and prioritization for the list?","index":390,"end_time":1489.47,"speaker_id":1,"start_time":1482.58,"speaker_name":"vivian"},{"text":"Yeah, so I haven''t.","index":391,"end_time":1493.87,"speaker_id":0,"start_time":1490.67,"speaker_name":"Tristan Pelligrino"},{"text":"Haven''t pulled up Salesforce to look at the records there, but at least I don''t.","index":392,"end_time":1499.39,"speaker_id":0,"start_time":1494.03,"speaker_name":"Tristan Pelligrino"},{"text":"I mean, I don''t have it here, but from what I remember, we would probably want to clean that up in.","index":393,"end_time":1509.03,"speaker_id":0,"start_time":1499.39,"speaker_name":"Tristan Pelligrino"},{"text":"In Salesforce itself.","index":394,"end_time":1510.07,"speaker_id":0,"start_time":1509.03,"speaker_name":"Tristan Pelligrino"},{"text":"And we could actually export all the data and clean it up outside of Salesforce using, you know, we could pick some data attributes like creation date or, you know, whether they''ve had an opportunity, a certain point in time.","index":395,"end_time":1524.74,"speaker_id":0,"start_time":1510.07,"speaker_name":"Tristan Pelligrino"},{"text":"And then we would have to probably work with Kyle and Maria to ask, like, the best way to clean up those records.","index":396,"end_time":1531.7,"speaker_id":0,"start_time":1525.14,"speaker_name":"Tristan Pelligrino"},{"text":"You know, are we deleting those?","index":397,"end_time":1533.14,"speaker_id":0,"start_time":1531.7,"speaker_name":"Tristan Pelligrino"},{"text":"Is there a process that.","index":398,"end_time":1534.82,"speaker_id":0,"start_time":1533.14,"speaker_name":"Tristan Pelligrino"},{"text":"That they would go through and recommend?","index":399,"end_time":1536.82,"speaker_id":0,"start_time":1534.82,"speaker_name":"Tristan Pelligrino"},{"text":"And then once they''re.","index":400,"end_time":1539.95,"speaker_id":0,"start_time":1539.07,"speaker_name":"Tristan Pelligrino"},{"text":"Once we have the data cleaned up, then we would have to.","index":401,"end_time":1543.55,"speaker_id":0,"start_time":1540.11,"speaker_name":"Tristan Pelligrino"},{"text":"There will be some fields we''ll have to add to Salesforce as well as HubSpot does.","index":402,"end_time":1547.75,"speaker_id":0,"start_time":1543.79,"speaker_name":"Tristan Pelligrino"},{"text":"That''s the custom mapping that we do.","index":403,"end_time":1549.47,"speaker_id":0,"start_time":1547.75,"speaker_name":"Tristan Pelligrino"},{"text":"We identified some of those custom fields and then we would turn it on and then we''re in sync.","index":404,"end_time":1554.27,"speaker_id":0,"start_time":1549.71,"speaker_name":"Tristan Pelligrino"},{"text":"And I think the big thing that we would want to do is make sure that the lists that are priority for you all is that they are included in that.","index":405,"end_time":1563.71,"speaker_id":0,"start_time":1554.27,"speaker_name":"Tristan Pelligrino"},{"text":"That cleaned up Salesforce list that we have.","index":406,"end_time":1567.72,"speaker_id":0,"start_time":1564.52,"speaker_name":"Tristan Pelligrino"},{"text":"Okay.","index":407,"end_time":1569.08,"speaker_id":2,"start_time":1568.52,"speaker_name":"bwillans"},{"text":"And you''ll guide us through what needs to happen.","index":408,"end_time":1571.88,"speaker_id":1,"start_time":1569.56,"speaker_name":"vivian"},{"text":"Right, to determine that.","index":409,"end_time":1573.96,"speaker_id":1,"start_time":1571.88,"speaker_name":"vivian"},{"text":"17,000, like, you''ll kind of guide us.","index":410,"end_time":1576.08,"speaker_id":1,"start_time":1574.2,"speaker_name":"vivian"},{"text":"Like, step one, please do this.","index":411,"end_time":1577.56,"speaker_id":1,"start_time":1576.08,"speaker_name":"vivian"},{"text":"Step two, please give me your parameters for X.","index":412,"end_time":1581.24,"speaker_id":1,"start_time":1577.88,"speaker_name":"vivian"},{"text":"Like, you''ll guide us kind of through.","index":413,"end_time":1583.56,"speaker_id":1,"start_time":1581.24,"speaker_name":"vivian"},{"text":"Like, is there any proactive work that we need to do now or do we just kind of wait until you kind of guide us through it?","index":414,"end_time":1589.4,"speaker_id":1,"start_time":1583.64,"speaker_name":"vivian"},{"text":"Yeah, what we''ll do is really just try to ask what is going to determine whether it''s a valid contact or not.","index":415,"end_time":1598.45,"speaker_id":0,"start_time":1590.29,"speaker_name":"Tristan Pelligrino"},{"text":"What data can point us in that direction?","index":416,"end_time":1602.85,"speaker_id":0,"start_time":1600.45,"speaker_name":"Tristan Pelligrino"},{"text":"There are a couple things that we could do right away that could probably clean up a large percentage of those.","index":417,"end_time":1611.29,"speaker_id":0,"start_time":1604.21,"speaker_name":"Tristan Pelligrino"},{"text":"For example, we could export all the contacts from.","index":418,"end_time":1615.27,"speaker_id":0,"start_time":1611.29,"speaker_name":"Tristan Pelligrino"},{"text":"From Salesforce and then we could run them all through an Email validation service and just say, hey, is this even a valid email anymore?","index":419,"end_time":1623.66,"speaker_id":0,"start_time":1615.42,"speaker_name":"Tristan Pelligrino"},{"text":"And for those that bounce, then we just say, like, 5,000 of these aren''t even valid, people.","index":420,"end_time":1629.26,"speaker_id":0,"start_time":1623.66,"speaker_name":"Tristan Pelligrino"},{"text":"Wonderful.","index":421,"end_time":1630.22,"speaker_id":1,"start_time":1629.58,"speaker_name":"vivian"},{"text":"Delete them.","index":422,"end_time":1630.86,"speaker_id":0,"start_time":1630.22,"speaker_name":"Tristan Pelligrino"},{"text":"That''s one thing.","index":423,"end_time":1631.379,"speaker_id":0,"start_time":1630.86,"speaker_name":"Tristan Pelligrino"},{"text":"I love that.","index":424,"end_time":1631.9,"speaker_id":2,"start_time":1631.379,"speaker_name":"bwillans"},{"text":"Yep.","index":425,"end_time":1632.7,"speaker_id":2,"start_time":1632.14,"speaker_name":"bwillans"},{"text":"Yeah.","index":426,"end_time":1633.26,"speaker_id":2,"start_time":1632.7,"speaker_name":"bwillans"},{"text":"There''s also some other things depending on how complex we want to get.","index":427,"end_time":1637.78,"speaker_id":0,"start_time":1634.54,"speaker_name":"Tristan Pelligrino"},{"text":"Like, we could also check the individual to their company and see if that also is still valid.","index":428,"end_time":1645.28,"speaker_id":0,"start_time":1637.78,"speaker_name":"Tristan Pelligrino"},{"text":"Their LinkedIn profiles, stuff like that as well.","index":429,"end_time":1649.44,"speaker_id":0,"start_time":1645.28,"speaker_name":"Tristan Pelligrino"},{"text":"And there''s probably just some junk leads I would expect in context that just, you know, emails aren''t valid.","index":430,"end_time":1656.88,"speaker_id":0,"start_time":1650.64,"speaker_name":"Tristan Pelligrino"},{"text":"So just kind of cleanse it from.","index":431,"end_time":1658.44,"speaker_id":0,"start_time":1656.88,"speaker_name":"Tristan Pelligrino"},{"text":"From that standpoint and then from there.","index":432,"end_time":1661.36,"speaker_id":0,"start_time":1658.44,"speaker_name":"Tristan Pelligrino"},{"text":"Vivian, it''s.","index":433,"end_time":1662.24,"speaker_id":0,"start_time":1661.36,"speaker_name":"Tristan Pelligrino"},{"text":"It''s about, like, what other data exists on these records that would tell us or help us make a decision or not.","index":434,"end_time":1669.12,"speaker_id":0,"start_time":1662.32,"speaker_name":"Tristan Pelligrino"},{"text":"Like, okay, maybe the source of the data or, you know, we would have to think through that.","index":435,"end_time":1676.77,"speaker_id":0,"start_time":1669.12,"speaker_name":"Tristan Pelligrino"},{"text":"But it''s like, basically, what data do we have that could help us clean it out?","index":436,"end_time":1681.49,"speaker_id":0,"start_time":1676.77,"speaker_name":"Tristan Pelligrino"},{"text":"Okay.","index":437,"end_time":1682.53,"speaker_id":1,"start_time":1681.97,"speaker_name":"vivian"},{"text":"Barb, would it help if I just.","index":438,"end_time":1685.41,"speaker_id":1,"start_time":1683.65,"speaker_name":"vivian"},{"text":"I''ll take the first pass, but I''ll definitely need your input on this as well.","index":439,"end_time":1689.25,"speaker_id":1,"start_time":1685.41,"speaker_name":"vivian"},{"text":"Like, what I can do is like, Kyle, a long time ago, he sent me a list of all the, like, the fields in Salesforce, and I can look at those fields again and be like, well, like, if we were to do segmentation, would we use this field?","index":440,"end_time":1704.27,"speaker_id":1,"start_time":1689.25,"speaker_name":"vivian"},{"text":"Like, would that be helpful for me to just take the first pass and then come back to you with that.","index":441,"end_time":1709.99,"speaker_id":1,"start_time":1704.27,"speaker_name":"vivian"},{"text":"If you have bandwidth?","index":442,"end_time":1713.19,"speaker_id":2,"start_time":1712.15,"speaker_name":"bwillans"},{"text":"Sure.","index":443,"end_time":1713.43,"speaker_id":2,"start_time":1713.19,"speaker_name":"bwillans"},{"text":"Or I can do it.","index":444,"end_time":1714.23,"speaker_id":2,"start_time":1713.43,"speaker_name":"bwillans"},{"text":"Yep.","index":445,"end_time":1714.67,"speaker_id":2,"start_time":1714.23,"speaker_name":"bwillans"},{"text":"Either way.","index":446,"end_time":1715.27,"speaker_id":2,"start_time":1714.67,"speaker_name":"bwillans"},{"text":"Okay.","index":447,"end_time":1717.51,"speaker_id":1,"start_time":1716.95,"speaker_name":"vivian"},{"text":"Yeah, let''s do it together.","index":448,"end_time":1723.67,"speaker_id":1,"start_time":1721.43,"speaker_name":"vivian"},{"text":"But I can.","index":449,"end_time":1724.43,"speaker_id":1,"start_time":1723.67,"speaker_name":"vivian"},{"text":"I can pull all the data first and then.","index":450,"end_time":1726.95,"speaker_id":1,"start_time":1724.43,"speaker_name":"vivian"},{"text":"And then, and then.","index":451,"end_time":1728.71,"speaker_id":1,"start_time":1727.59,"speaker_name":"vivian"},{"text":"And then we can.","index":452,"end_time":1729.59,"speaker_id":1,"start_time":1728.71,"speaker_name":"vivian"},{"text":"We can determine.","index":453,"end_time":1730.71,"speaker_id":1,"start_time":1729.59,"speaker_name":"vivian"},{"text":"Sure.","index":454,"end_time":1734.47,"speaker_id":1,"start_time":1734.07,"speaker_name":"vivian"},{"text":"Yeah.","index":455,"end_time":1735.35,"speaker_id":1,"start_time":1734.87,"speaker_name":"vivian"},{"text":"Because I wanted to.","index":456,"end_time":1736.07,"speaker_id":1,"start_time":1735.35,"speaker_name":"vivian"},{"text":"Yeah.","index":457,"end_time":1736.55,"speaker_id":1,"start_time":1736.07,"speaker_name":"vivian"},{"text":"To help out somewhere, and I think database was.","index":458,"end_time":1739.51,"speaker_id":1,"start_time":1736.87,"speaker_name":"vivian"},{"text":"Was one of them.","index":459,"end_time":1740.31,"speaker_id":1,"start_time":1739.51,"speaker_name":"vivian"},{"text":"When do you need the spy, Tristan?","index":460,"end_time":1746.39,"speaker_id":1,"start_time":1743.269,"speaker_name":"vivian"},{"text":"Like, what''s the deadline?","index":461,"end_time":1747.59,"speaker_id":1,"start_time":1746.47,"speaker_name":"vivian"},{"text":"I work well with deadlines.","index":462,"end_time":1749.31,"speaker_id":1,"start_time":1747.83,"speaker_name":"vivian"},{"text":"You just have to give me the deadline.","index":463,"end_time":1750.63,"speaker_id":1,"start_time":1749.31,"speaker_name":"vivian"},{"text":"Let''s see.","index":464,"end_time":1752.63,"speaker_id":0,"start_time":1751.91,"speaker_name":"Tristan Pelligrino"},{"text":"I would have to go through.","index":465,"end_time":1754.24,"speaker_id":0,"start_time":1753.12,"speaker_name":"Tristan Pelligrino"},{"text":"Well, it''s.","index":466,"end_time":1762.48,"speaker_id":0,"start_time":1761.52,"speaker_name":"Tristan Pelligrino"},{"text":"So the data cleansing piece we can almost do.","index":467,"end_time":1765.12,"speaker_id":0,"start_time":1762.8,"speaker_name":"Tristan Pelligrino"},{"text":"It''s not like a pure dependency because there''s still some test records we can do.","index":468,"end_time":1769.68,"speaker_id":0,"start_time":1765.92,"speaker_name":"Tristan Pelligrino"},{"text":"We can do configuration.","index":469,"end_time":1770.88,"speaker_id":0,"start_time":1769.68,"speaker_name":"Tristan Pelligrino"},{"text":"Like.","index":470,"end_time":1771.36,"speaker_id":0,"start_time":1770.96,"speaker_name":"Tristan Pelligrino"},{"text":"Yeah, I''m trying to think, like, first week of December.","index":471,"end_time":1776.56,"speaker_id":0,"start_time":1771.44,"speaker_name":"Tristan Pelligrino"},{"text":"So, like, after you come back from Thanksgiving, that Friday after.","index":472,"end_time":1779.28,"speaker_id":0,"start_time":1776.56,"speaker_name":"Tristan Pelligrino"},{"text":"Would that be fair?","index":473,"end_time":1780.48,"speaker_id":0,"start_time":1779.36,"speaker_name":"Tristan Pelligrino"},{"text":"Yeah, I think that would give us a good starting point and then we can figure out from there how further we need to trim or clean up the data from that standpoint.","index":474,"end_time":1793.37,"speaker_id":0,"start_time":1782.57,"speaker_name":"Tristan Pelligrino"},{"text":"Okay.","index":475,"end_time":1795.05,"speaker_id":1,"start_time":1794.41,"speaker_name":"vivian"},{"text":"How do I put it?","index":476,"end_time":1798.61,"speaker_id":1,"start_time":1797.45,"speaker_name":"vivian"},{"text":"And maybe I''m complicating this or whatnot literally.","index":477,"end_time":1803.61,"speaker_id":1,"start_time":1798.61,"speaker_name":"vivian"},{"text":"I''m going to pull.","index":478,"end_time":1804.49,"speaker_id":1,"start_time":1803.61,"speaker_name":"vivian"},{"text":"Get Kyle to give me the fields and then I''ll be like, hey, if you look at this field and this field and this field, it''ll tell us who our existing customers are.","index":479,"end_time":1814.23,"speaker_id":1,"start_time":1805.69,"speaker_name":"vivian"},{"text":"We want to like, import those in.","index":480,"end_time":1816.31,"speaker_id":1,"start_time":1814.39,"speaker_name":"vivian"},{"text":"If you show me this field and this field, this will show me all the net new prospects that are like, that are like high, high, high profile.","index":481,"end_time":1829.75,"speaker_id":1,"start_time":1816.63,"speaker_name":"vivian"},{"text":"Like, like that.","index":482,"end_time":1830.43,"speaker_id":1,"start_time":1829.75,"speaker_name":"vivian"},{"text":"We, like, that are like more pos.","index":483,"end_time":1833.27,"speaker_id":1,"start_time":1830.43,"speaker_name":"vivian"},{"text":"Like that have showed some, like, engagement over the last two years, you know, like, do you know what I mean?","index":484,"end_time":1839.23,"speaker_id":1,"start_time":1833.35,"speaker_name":"vivian"},{"text":"Like, I''m lit.","index":485,"end_time":1840.56,"speaker_id":1,"start_time":1839.23,"speaker_name":"vivian"},{"text":"Is.","index":486,"end_time":1841.04,"speaker_id":1,"start_time":1840.64,"speaker_name":"vivian"},{"text":"Is that enough?","index":487,"end_time":1841.84,"speaker_id":1,"start_time":1841.04,"speaker_name":"vivian"},{"text":"Is that what you need?","index":488,"end_time":1843.04,"speaker_id":1,"start_time":1841.92,"speaker_name":"vivian"},{"text":"I think so, yeah.","index":489,"end_time":1845.16,"speaker_id":0,"start_time":1844,"speaker_name":"Tristan Pelligrino"},{"text":"I mean, realistically, Vivian, we''re probably looking at like five to eight fields.","index":490,"end_time":1849.64,"speaker_id":0,"start_time":1845.16,"speaker_name":"Tristan Pelligrino"},{"text":"That would drive most of the.","index":491,"end_time":1851.04,"speaker_id":0,"start_time":1849.64,"speaker_name":"Tristan Pelligrino"},{"text":"Exactly.","index":492,"end_time":1851.92,"speaker_id":1,"start_time":1851.2,"speaker_name":"vivian"},{"text":"Okay.","index":493,"end_time":1853.24,"speaker_id":2,"start_time":1852.88,"speaker_name":"bwillans"},{"text":"I''m not.","index":494,"end_time":1853.56,"speaker_id":2,"start_time":1853.24,"speaker_name":"bwillans"},{"text":"Okay, thank you.","index":495,"end_time":1854.36,"speaker_id":1,"start_time":1853.56,"speaker_name":"vivian"},{"text":"I won''t overthink it.","index":496,"end_time":1855.52,"speaker_id":1,"start_time":1854.36,"speaker_name":"vivian"},{"text":"I''ll.","index":497,"end_time":1855.84,"speaker_id":1,"start_time":1855.52,"speaker_name":"vivian"},{"text":"I''ll identify the 5 or 6.","index":498,"end_time":1857.24,"speaker_id":1,"start_time":1855.84,"speaker_name":"vivian"},{"text":"So thank you for that guidance.","index":499,"end_time":1858.4,"speaker_id":1,"start_time":1857.24,"speaker_name":"vivian"},{"text":"Yeah, for sure.","index":500,"end_time":1859.36,"speaker_id":0,"start_time":1858.4,"speaker_name":"Tristan Pelligrino"},{"text":"Okay.","index":501,"end_time":1860.4,"speaker_id":2,"start_time":1859.84,"speaker_name":"bwillans"},{"text":"Let''S see.","index":502,"end_time":1863.52,"speaker_id":0,"start_time":1862.88,"speaker_name":"Tristan Pelligrino"},{"text":"So that.","index":503,"end_time":1864.32,"speaker_id":0,"start_time":1863.68,"speaker_name":"Tristan Pelligrino"},{"text":"That covers the.","index":504,"end_time":1866.05,"speaker_id":0,"start_time":1865.29,"speaker_name":"Tristan Pelligrino"},{"text":"Oh, there''s segment lists, though.","index":505,"end_time":1868.57,"speaker_id":0,"start_time":1866.05,"speaker_name":"Tristan Pelligrino"},{"text":"Is that.","index":506,"end_time":1870.09,"speaker_id":0,"start_time":1869.61,"speaker_name":"Tristan Pelligrino"},{"text":"Is that what we''re talking about?","index":507,"end_time":1871.05,"speaker_id":0,"start_time":1870.09,"speaker_name":"Tristan Pelligrino"},{"text":"Is there something from Marketo that you want to make sure that you don''t lose?","index":508,"end_time":1874.17,"speaker_id":0,"start_time":1871.05,"speaker_name":"Tristan Pelligrino"},{"text":"I think, Barb, you had mentioned something along those lines.","index":509,"end_time":1876.49,"speaker_id":0,"start_time":1874.17,"speaker_name":"Tristan Pelligrino"},{"text":"I just think the activities.","index":510,"end_time":1878.73,"speaker_id":2,"start_time":1876.65,"speaker_name":"bwillans"},{"text":"It''s what Blake had said to me.","index":511,"end_time":1880.85,"speaker_id":2,"start_time":1878.97,"speaker_name":"bwillans"},{"text":"He''s the bdr.","index":512,"end_time":1881.77,"speaker_id":2,"start_time":1880.85,"speaker_name":"bwillans"},{"text":"He just doesn''t want to lose anything that came across.","index":513,"end_time":1884.57,"speaker_id":2,"start_time":1882.25,"speaker_name":"bwillans"},{"text":"But quite frankly, I don''t think there was a lot that came across, but it''s.","index":514,"end_time":1889.53,"speaker_id":2,"start_time":1884.65,"speaker_name":"bwillans"},{"text":"He just didn''t want to lose it.","index":515,"end_time":1890.89,"speaker_id":2,"start_time":1889.61,"speaker_name":"bwillans"},{"text":"So that is one thing, though.","index":516,"end_time":1892.7,"speaker_id":0,"start_time":1890.89,"speaker_name":"Tristan Pelligrino"},{"text":"I think it''s a good question.","index":517,"end_time":1893.98,"speaker_id":0,"start_time":1892.78,"speaker_name":"Tristan Pelligrino"},{"text":"It''s basically, we could do that in a note field.","index":518,"end_time":1897.98,"speaker_id":0,"start_time":1895.74,"speaker_name":"Tristan Pelligrino"},{"text":"I mean, Barb, you''ve seen where we''ve combined notes in a single field before.","index":519,"end_time":1902.94,"speaker_id":0,"start_time":1899.34,"speaker_name":"Tristan Pelligrino"},{"text":"That might be something we do.","index":520,"end_time":1905.18,"speaker_id":0,"start_time":1903.82,"speaker_name":"Tristan Pelligrino"},{"text":"Because the question is what activity, data or notes do we have in Marketo that never got to Salesforce?","index":521,"end_time":1913.42,"speaker_id":0,"start_time":1905.34,"speaker_name":"Tristan Pelligrino"},{"text":"Do we want that to appear in HubSpot?","index":522,"end_time":1916.78,"speaker_id":0,"start_time":1914.3,"speaker_name":"Tristan Pelligrino"},{"text":"Is that what we''re.","index":523,"end_time":1917.95,"speaker_id":0,"start_time":1917.19,"speaker_name":"Tristan Pelligrino"},{"text":"We''re kind of referencing or.","index":524,"end_time":1919.35,"speaker_id":0,"start_time":1917.95,"speaker_name":"Tristan Pelligrino"},{"text":"I think so, yeah.","index":525,"end_time":1920.95,"speaker_id":2,"start_time":1919.99,"speaker_name":"bwillans"},{"text":"So I think.","index":526,"end_time":1921.59,"speaker_id":2,"start_time":1920.95,"speaker_name":"bwillans"},{"text":"And it''s not tragic like it.","index":527,"end_time":1923.99,"speaker_id":2,"start_time":1922.15,"speaker_name":"bwillans"},{"text":"It''s not.","index":528,"end_time":1924.71,"speaker_id":2,"start_time":1924.15,"speaker_name":"bwillans"},{"text":"It''s just something that we.","index":529,"end_time":1926.15,"speaker_id":2,"start_time":1924.79,"speaker_name":"bwillans"},{"text":"It''s an opportunity.","index":530,"end_time":1927.47,"speaker_id":2,"start_time":1926.39,"speaker_name":"bwillans"},{"text":"Right.","index":531,"end_time":1927.79,"speaker_id":2,"start_time":1927.47,"speaker_name":"bwillans"},{"text":"So, for instance, yesterday we uploaded a list.","index":532,"end_time":1930.71,"speaker_id":2,"start_time":1927.79,"speaker_name":"bwillans"},{"text":"We had three options to put in some notes.","index":533,"end_time":1934.47,"speaker_id":2,"start_time":1931.03,"speaker_name":"bwillans"},{"text":"One was high value reference and review.","index":534,"end_time":1939.27,"speaker_id":2,"start_time":1934.87,"speaker_name":"bwillans"},{"text":"You know, we just want to make sure that when that goes over to Salesforce, we.","index":535,"end_time":1945.39,"speaker_id":2,"start_time":1939.99,"speaker_name":"bwillans"},{"text":"They still get it back into.","index":536,"end_time":1947.03,"speaker_id":2,"start_time":1945.39,"speaker_name":"bwillans"},{"text":"We still get it back as a marketing arm into HubSpot, so we know what to do and.","index":537,"end_time":1953.93,"speaker_id":2,"start_time":1948.33,"speaker_name":"bwillans"},{"text":"Yeah, yeah, but it was all.","index":538,"end_time":1956.25,"speaker_id":2,"start_time":1954.49,"speaker_name":"bwillans"},{"text":"It''s all good.","index":539,"end_time":1956.97,"speaker_id":2,"start_time":1956.25,"speaker_name":"bwillans"},{"text":"Like, it was all really, really good information.","index":540,"end_time":1958.97,"speaker_id":2,"start_time":1956.97,"speaker_name":"bwillans"},{"text":"So we just want to make sure that we want to keep it.","index":541,"end_time":1961.93,"speaker_id":2,"start_time":1959.21,"speaker_name":"bwillans"},{"text":"Yes.","index":542,"end_time":1962.49,"speaker_id":0,"start_time":1962.09,"speaker_name":"Tristan Pelligrino"},{"text":"There''s two things we can do there.","index":543,"end_time":1964.01,"speaker_id":0,"start_time":1962.49,"speaker_name":"Tristan Pelligrino"},{"text":"So we have, you know, basically we just need email address and then we can concatenate fields or something from Marketo and Guille.","index":544,"end_time":1971.61,"speaker_id":0,"start_time":1964.01,"speaker_name":"Tristan Pelligrino"},{"text":"That what we would do there is either store it in a custom field.","index":545,"end_time":1975.7,"speaker_id":0,"start_time":1971.61,"speaker_name":"Tristan Pelligrino"},{"text":"There would be like historical data from Marketo, or we could create an event and add an event and just say, you know, Basically it''s the HubSpot data entry event.","index":546,"end_time":1992.34,"speaker_id":0,"start_time":1975.86,"speaker_name":"Tristan Pelligrino"},{"text":"So whenever that record got created in HubSpot, here''s the notes that we had in Marketo at that point in time.","index":547,"end_time":1998.9,"speaker_id":0,"start_time":1992.42,"speaker_name":"Tristan Pelligrino"},{"text":"And so it''d be stamped on that contact record.","index":548,"end_time":2002.02,"speaker_id":0,"start_time":1998.9,"speaker_name":"Tristan Pelligrino"},{"text":"So there''s a couple approaches we could do there.","index":549,"end_time":2004.1,"speaker_id":0,"start_time":2002.1,"speaker_name":"Tristan Pelligrino"},{"text":"That''d be great.","index":550,"end_time":2005.36,"speaker_id":2,"start_time":2004.76,"speaker_name":"bwillans"},{"text":"Yeah, we just don''t want to lose that.","index":551,"end_time":2006.92,"speaker_id":2,"start_time":2005.36,"speaker_name":"bwillans"},{"text":"When I was speaking to Blake, awesome bdr and he''s just like, well, I just don''t want to lose all of those notes.","index":552,"end_time":2013.6,"speaker_id":2,"start_time":2007.48,"speaker_name":"bwillans"},{"text":"Right.","index":553,"end_time":2013.8,"speaker_id":2,"start_time":2013.6,"speaker_name":"bwillans"},{"text":"Like, I just want to.","index":554,"end_time":2014.76,"speaker_id":2,"start_time":2013.8,"speaker_name":"bwillans"},{"text":"I. I want to move, but I don''t want to move my.","index":555,"end_time":2018.04,"speaker_id":2,"start_time":2014.84,"speaker_name":"bwillans"},{"text":"My history.","index":556,"end_time":2019,"speaker_id":2,"start_time":2018.36,"speaker_name":"bwillans"},{"text":"So we want to make sure that he knows who he''s talking to when it''s coming, when marketing is still, you know, nurturing within HubSpot.","index":557,"end_time":2029.48,"speaker_id":2,"start_time":2019.4,"speaker_name":"bwillans"},{"text":"He still gets those notes when it goes back to HubSpot or, sorry, Salesforce.","index":558,"end_time":2034.11,"speaker_id":2,"start_time":2029.48,"speaker_name":"bwillans"},{"text":"Yeah, yeah, yeah.","index":559,"end_time":2036.03,"speaker_id":0,"start_time":2034.35,"speaker_name":"Tristan Pelligrino"},{"text":"And so there''s.","index":560,"end_time":2037.31,"speaker_id":0,"start_time":2036.27,"speaker_name":"Tristan Pelligrino"},{"text":"There''s the history piece, and then there''s also the question of where do notes or information reside moving forward from HubSpot to Salesforce 2.","index":561,"end_time":2046.51,"speaker_id":0,"start_time":2037.31,"speaker_name":"Tristan Pelligrino"},{"text":"So I actually, the more I think about it, probably be an event type that we would stamp.","index":562,"end_time":2052.35,"speaker_id":0,"start_time":2046.99,"speaker_name":"Tristan Pelligrino"},{"text":"And then what we could do is just include events, all events from HubSpot to Salesforce.","index":563,"end_time":2057.75,"speaker_id":0,"start_time":2052.35,"speaker_name":"Tristan Pelligrino"},{"text":"And so you''d be able to see all of that in one place.","index":564,"end_time":2060.89,"speaker_id":0,"start_time":2057.75,"speaker_name":"Tristan Pelligrino"},{"text":"All right.","index":565,"end_time":2063.37,"speaker_id":2,"start_time":2062.81,"speaker_name":"bwillans"},{"text":"Is that a decision to make right.","index":566,"end_time":2065.09,"speaker_id":2,"start_time":2063.45,"speaker_name":"bwillans"},{"text":"Now or.","index":567,"end_time":2065.69,"speaker_id":1,"start_time":2065.09,"speaker_name":"vivian"},{"text":"We need to add it to what we have.","index":568,"end_time":2070.01,"speaker_id":0,"start_time":2068.41,"speaker_name":"Tristan Pelligrino"},{"text":"Yeah.","index":569,"end_time":2070.73,"speaker_id":0,"start_time":2070.25,"speaker_name":"Tristan Pelligrino"},{"text":"So I think how we''ll respond to is like, your requirement is to get that historical data and then we''ll.","index":570,"end_time":2077.37,"speaker_id":0,"start_time":2070.73,"speaker_name":"Tristan Pelligrino"},{"text":"We''ll provide a way to.","index":571,"end_time":2078.85,"speaker_id":0,"start_time":2077.61,"speaker_name":"Tristan Pelligrino"},{"text":"To do that, like a recommendation.","index":572,"end_time":2080.37,"speaker_id":0,"start_time":2078.85,"speaker_name":"Tristan Pelligrino"},{"text":"That''s how I think.","index":573,"end_time":2081.85,"speaker_id":0,"start_time":2080.37,"speaker_name":"Tristan Pelligrino"},{"text":"Okay.","index":574,"end_time":2083.29,"speaker_id":2,"start_time":2082.73,"speaker_name":"bwillans"},{"text":"All right.","index":575,"end_time":2084.17,"speaker_id":2,"start_time":2083.61,"speaker_name":"bwillans"},{"text":"All right, we''ve got next here.","index":576,"end_time":2088.619,"speaker_id":0,"start_time":2086.219,"speaker_name":"Tristan Pelligrino"},{"text":"Oh, number four.","index":577,"end_time":2091.659,"speaker_id":0,"start_time":2090.699,"speaker_name":"Tristan Pelligrino"},{"text":"James.","index":578,"end_time":2092.619,"speaker_id":0,"start_time":2092.139,"speaker_name":"Tristan Pelligrino"},{"text":"Yeah.","index":579,"end_time":2093.979,"speaker_id":2,"start_time":2093.499,"speaker_name":"bwillans"},{"text":"And web chat.","index":580,"end_time":2094.779,"speaker_id":0,"start_time":2093.979,"speaker_name":"Tristan Pelligrino"},{"text":"Yeah.","index":581,"end_time":2095.179,"speaker_id":0,"start_time":2094.779,"speaker_name":"Tristan Pelligrino"},{"text":"Yeah.","index":582,"end_time":2097.979,"speaker_id":2,"start_time":2097.579,"speaker_name":"bwillans"},{"text":"You met James, so I reached out to him for a hosting environment.","index":583,"end_time":2101.739,"speaker_id":2,"start_time":2097.979,"speaker_name":"bwillans"},{"text":"You have WordPress access, but I''m not sure how that.","index":584,"end_time":2105.899,"speaker_id":2,"start_time":2102.699,"speaker_name":"bwillans"},{"text":"How does that map to the recreation of all of the forms in Marketo and what else do you need?","index":585,"end_time":2114.35,"speaker_id":2,"start_time":2107.099,"speaker_name":"bwillans"},{"text":"So I know you need a hosting environment, but do you have everything you need to start that Recreation.","index":586,"end_time":2119.75,"speaker_id":2,"start_time":2114.35,"speaker_name":"bwillans"},{"text":"Yeah.","index":587,"end_time":2120.83,"speaker_id":0,"start_time":2120.39,"speaker_name":"Tristan Pelligrino"},{"text":"So for, for the WordPress environment.","index":588,"end_time":2123.19,"speaker_id":0,"start_time":2120.83,"speaker_name":"Tristan Pelligrino"},{"text":"Yeah, we have, remind me, WP Engine, right?","index":589,"end_time":2128.55,"speaker_id":0,"start_time":2124.55,"speaker_name":"Tristan Pelligrino"},{"text":"Is that what it is?","index":590,"end_time":2129.51,"speaker_id":0,"start_time":2128.63,"speaker_name":"Tristan Pelligrino"},{"text":"Yeah.","index":591,"end_time":2130.31,"speaker_id":0,"start_time":2129.91,"speaker_name":"Tristan Pelligrino"},{"text":"So WP Engine, we have a WordPress environment, just those forms just like whenever we want to cut over.","index":592,"end_time":2135.59,"speaker_id":0,"start_time":2130.31,"speaker_name":"Tristan Pelligrino"},{"text":"What we would probably do, Barb, is create some test pages on WordPress just with some of the HubSpot forms.","index":593,"end_time":2142.01,"speaker_id":0,"start_time":2136.09,"speaker_name":"Tristan Pelligrino"},{"text":"Make sure that they''re getting pulled into HubSpot.","index":594,"end_time":2144.89,"speaker_id":0,"start_time":2142.09,"speaker_name":"Tristan Pelligrino"},{"text":"But nice thing about HubSpot, it''s very similar to Marketo.","index":595,"end_time":2148.13,"speaker_id":0,"start_time":2144.89,"speaker_name":"Tristan Pelligrino"},{"text":"It would be an embed code and so whenever we want to start using HubSpot, we would just swap out those forms.","index":596,"end_time":2156.33,"speaker_id":0,"start_time":2148.13,"speaker_name":"Tristan Pelligrino"},{"text":"It''s a pretty straightforward process, so not like a big code change or anything.","index":597,"end_time":2162.97,"speaker_id":0,"start_time":2156.89,"speaker_name":"Tristan Pelligrino"},{"text":"Okay.","index":598,"end_time":2164.28,"speaker_id":1,"start_time":2163.88,"speaker_name":"vivian"},{"text":"So if I get you the, the, the hosting and he''s great like you, you''ve met him.","index":599,"end_time":2170.04,"speaker_id":2,"start_time":2164.6,"speaker_name":"bwillans"},{"text":"If I get the hosting environment, you''re good to be able to do that.","index":600,"end_time":2173.64,"speaker_id":2,"start_time":2170.44,"speaker_name":"bwillans"},{"text":"Yeah, yeah, that''s all, that''s all we need.","index":601,"end_time":2176.64,"speaker_id":0,"start_time":2174.36,"speaker_name":"Tristan Pelligrino"},{"text":"The hosting environment is more important just to make sure we have database access and then also to create a staging environment if we want to go in that direction.","index":602,"end_time":2186.44,"speaker_id":0,"start_time":2176.64,"speaker_name":"Tristan Pelligrino"},{"text":"Because I don''t think you all are using staging right now.","index":603,"end_time":2189,"speaker_id":0,"start_time":2186.44,"speaker_name":"Tristan Pelligrino"},{"text":"From.","index":604,"end_time":2189.62,"speaker_id":0,"start_time":2189.38,"speaker_name":"Tristan Pelligrino"},{"text":"We''re not.","index":605,"end_time":2190.18,"speaker_id":2,"start_time":2189.62,"speaker_name":"bwillans"},{"text":"We go straight to production, which is, which is fine right now, but not if we''re moving to something a little bit more sophisticated.","index":606,"end_time":2200.82,"speaker_id":2,"start_time":2190.5,"speaker_name":"bwillans"},{"text":"Like it''s, it''s fine right now.","index":607,"end_time":2202.3,"speaker_id":2,"start_time":2200.9,"speaker_name":"bwillans"},{"text":"It''s, it works.","index":608,"end_time":2203.3,"speaker_id":2,"start_time":2202.3,"speaker_name":"bwillans"},{"text":"But I think moving ahead, we, we need a staging environment for sure.","index":609,"end_time":2206.98,"speaker_id":2,"start_time":2203.54,"speaker_name":"bwillans"},{"text":"Yeah.","index":610,"end_time":2207.58,"speaker_id":0,"start_time":2207.22,"speaker_name":"Tristan Pelligrino"},{"text":"And I think you probably, you know us, we, we would like to probably create a mirror of, of the live site and, and do some of these early changes and staging to test and things.","index":611,"end_time":2217.98,"speaker_id":0,"start_time":2207.58,"speaker_name":"Tristan Pelligrino"},{"text":"And then that way we''re not really messing with the live environment.","index":612,"end_time":2221.57,"speaker_id":0,"start_time":2217.98,"speaker_name":"Tristan Pelligrino"},{"text":"So could I just ask, like, could we just, could you guys just have a short meeting with James to be like, hey James, here''s a, here''s like, you know, the five things that we''re going to do in the next little while.","index":613,"end_time":2232.53,"speaker_id":1,"start_time":2221.89,"speaker_name":"vivian"},{"text":"Give him like, let him know because right now he''s the only one that touches our WordPress and our website.","index":614,"end_time":2237.81,"speaker_id":1,"start_time":2232.53,"speaker_name":"vivian"},{"text":"And so it''s just good for him to like get some like in advance that the changes are about to happen.","index":615,"end_time":2243.25,"speaker_id":1,"start_time":2238.37,"speaker_name":"vivian"},{"text":"So we just.","index":616,"end_time":2244.73,"speaker_id":1,"start_time":2243.49,"speaker_name":"vivian"},{"text":"Making sure that we do that.","index":617,"end_time":2245.89,"speaker_id":1,"start_time":2244.73,"speaker_name":"vivian"},{"text":"Yep, we could do that.","index":618,"end_time":2249.24,"speaker_id":0,"start_time":2248.48,"speaker_name":"Tristan Pelligrino"},{"text":"Barb, you want to set that up totally fair?","index":619,"end_time":2252.64,"speaker_id":0,"start_time":2249.24,"speaker_name":"Tristan Pelligrino"},{"text":"Yeah, yeah, I will.","index":620,"end_time":2254.56,"speaker_id":2,"start_time":2252.64,"speaker_name":"bwillans"},{"text":"And he, he does a great job.","index":621,"end_time":2256.72,"speaker_id":2,"start_time":2255.12,"speaker_name":"bwillans"},{"text":"Yeah, we just go straight.","index":622,"end_time":2258.24,"speaker_id":2,"start_time":2256.72,"speaker_name":"bwillans"},{"text":"It''s so it, it, it''s a simple environment right now, which is awesome, but it goes straight to production.","index":623,"end_time":2264.72,"speaker_id":2,"start_time":2258.56,"speaker_name":"bwillans"},{"text":"But I think this is when we add the forms.","index":624,"end_time":2267.24,"speaker_id":2,"start_time":2264.72,"speaker_name":"bwillans"},{"text":"It''s it''s going to get a little bit more complex so it makes sense.","index":625,"end_time":2270.36,"speaker_id":2,"start_time":2267.24,"speaker_name":"bwillans"},{"text":"I''ll, I''ll set it up and he''s a really good guy.","index":626,"end_time":2272.64,"speaker_id":2,"start_time":2270.36,"speaker_name":"bwillans"},{"text":"All right.","index":627,"end_time":2273.93,"speaker_id":0,"start_time":2273.53,"speaker_name":"Tristan Pelligrino"},{"text":"And in the.","index":628,"end_time":2274.89,"speaker_id":0,"start_time":2274.17,"speaker_name":"Tristan Pelligrino"},{"text":"Are we talking about the form or the whims change that we wanted to make as well with the resources or is that separate?","index":629,"end_time":2281.29,"speaker_id":0,"start_time":2274.89,"speaker_name":"Tristan Pelligrino"},{"text":"Say both?","index":630,"end_time":2285.69,"speaker_id":2,"start_time":2285.05,"speaker_name":"bwillans"},{"text":"I think for me it was the adding, the removing the forms from Marketo.","index":631,"end_time":2293.45,"speaker_id":2,"start_time":2285.85,"speaker_name":"bwillans"},{"text":"But yeah.","index":632,"end_time":2295.61,"speaker_id":2,"start_time":2293.85,"speaker_name":"bwillans"},{"text":"Yeah.","index":633,"end_time":2297.93,"speaker_id":0,"start_time":2297.53,"speaker_name":"Tristan Pelligrino"},{"text":"So that P. And then so would James do the, the changes to the like the WIMS resources and things that we wrote up or how would you.","index":634,"end_time":2305.8,"speaker_id":0,"start_time":2297.93,"speaker_name":"Tristan Pelligrino"},{"text":"Oh, correct.","index":635,"end_time":2306.64,"speaker_id":2,"start_time":2305.88,"speaker_name":"bwillans"},{"text":"Yes.","index":636,"end_time":2307.08,"speaker_id":2,"start_time":2306.64,"speaker_name":"bwillans"},{"text":"Yeah, he does this as well.","index":637,"end_time":2308.44,"speaker_id":2,"start_time":2307.16,"speaker_name":"bwillans"},{"text":"Yeah.","index":638,"end_time":2308.84,"speaker_id":2,"start_time":2308.44,"speaker_name":"bwillans"},{"text":"Okay, gotcha.","index":639,"end_time":2310.76,"speaker_id":0,"start_time":2309.88,"speaker_name":"Tristan Pelligrino"},{"text":"So, so we would just.","index":640,"end_time":2311.96,"speaker_id":0,"start_time":2310.76,"speaker_name":"Tristan Pelligrino"},{"text":"Do you want us to design.","index":641,"end_time":2313.16,"speaker_id":0,"start_time":2311.96,"speaker_name":"Tristan Pelligrino"},{"text":"I guess that''s a, that''s a separate piece, but we would design that in, in Figma and then he would roll those changes out on, on the resources side.","index":642,"end_time":2321.48,"speaker_id":0,"start_time":2313.32,"speaker_name":"Tristan Pelligrino"},{"text":"Correct.","index":643,"end_time":2322.92,"speaker_id":2,"start_time":2322.36,"speaker_name":"bwillans"},{"text":"Okay, gotcha.","index":644,"end_time":2324.2,"speaker_id":0,"start_time":2322.92,"speaker_name":"Tristan Pelligrino"},{"text":"Yeah.","index":645,"end_time":2325.66,"speaker_id":0,"start_time":2325.42,"speaker_name":"Tristan Pelligrino"},{"text":"So that, yeah, I wouldn''t even be a.","index":646,"end_time":2328.06,"speaker_id":0,"start_time":2325.66,"speaker_name":"Tristan Pelligrino"},{"text":"We could probably do a 30 minute meeting just to, to walk James through.","index":647,"end_time":2332.54,"speaker_id":0,"start_time":2328.86,"speaker_name":"Tristan Pelligrino"},{"text":"But those are straightforward changes that, you know, won''t be a big problem.","index":648,"end_time":2336.94,"speaker_id":0,"start_time":2332.54,"speaker_name":"Tristan Pelligrino"},{"text":"All right, so Vivian, we''ve got number five here, the changeover from December to January.","index":649,"end_time":2346.46,"speaker_id":0,"start_time":2340.38,"speaker_name":"Tristan Pelligrino"},{"text":"So I''ll give you the example.","index":650,"end_time":2349.9,"speaker_id":1,"start_time":2348.38,"speaker_name":"vivian"},{"text":"We want to run a webinar for.","index":651,"end_time":2354.14,"speaker_id":1,"start_time":2351.58,"speaker_name":"vivian"},{"text":"We want to run a webinar in January, but in order to get people to the webinar in January you need to promote three to four weeks in advance.","index":652,"end_time":2363.02,"speaker_id":1,"start_time":2355.1,"speaker_name":"vivian"},{"text":"And so during this December and January period, is there a blackout period where it''s like, hey, don''t create anything like, you know, start creating stuff after this date.","index":653,"end_time":2373.5,"speaker_id":1,"start_time":2363.58,"speaker_name":"vivian"},{"text":"So it literally is just understanding when we can start doing some stuff in January and so just some guardrails on that.","index":654,"end_time":2383.01,"speaker_id":1,"start_time":2373.58,"speaker_name":"vivian"},{"text":"Yeah, it''s a good question.","index":655,"end_time":2388.53,"speaker_id":0,"start_time":2387.33,"speaker_name":"Tristan Pelligrino"},{"text":"Trying to think.","index":656,"end_time":2395.97,"speaker_id":0,"start_time":2395.09,"speaker_name":"Tristan Pelligrino"},{"text":"And are these known content, like are we distributing through email?","index":657,"end_time":2406.28,"speaker_id":0,"start_time":2400.37,"speaker_name":"Tristan Pelligrino"},{"text":"Are we also promoting through perhaps organic and paid as well?","index":658,"end_time":2410.6,"speaker_id":0,"start_time":2406.28,"speaker_name":"Tristan Pelligrino"},{"text":"Like what''s the, the plan there.","index":659,"end_time":2412.2,"speaker_id":0,"start_time":2410.6,"speaker_name":"Tristan Pelligrino"},{"text":"So I can jump in.","index":660,"end_time":2416.36,"speaker_id":2,"start_time":2415.24,"speaker_name":"bwillans"},{"text":"We had started, Colin and I through the pillar pillars of productivity and he was mirroring constant contact.","index":661,"end_time":2426.92,"speaker_id":2,"start_time":2417,"speaker_name":"bwillans"},{"text":"So that was kind of the first foray before we jumped 100 to HubSpot to away from Marketo to HubSpot.","index":662,"end_time":2439.31,"speaker_id":2,"start_time":2427.72,"speaker_name":"bwillans"},{"text":"So he and I are working on that to say, look, we needed to start with something.","index":663,"end_time":2444.03,"speaker_id":2,"start_time":2439.31,"speaker_name":"bwillans"},{"text":"Right, so you guys all have access to constant contact.","index":664,"end_time":2446.47,"speaker_id":2,"start_time":2444.03,"speaker_name":"bwillans"},{"text":"I''m starting to populate it over to make sure it''s rock solid before it goes into HubSpot.","index":665,"end_time":2454.67,"speaker_id":2,"start_time":2446.87,"speaker_name":"bwillans"},{"text":"So I don''t know that that''s a.","index":666,"end_time":2456.95,"speaker_id":2,"start_time":2454.67,"speaker_name":"bwillans"},{"text":"The right answer, but it''s a, it''s a drip answer that says we''re starting move it over before we add anything new.","index":667,"end_time":2466.33,"speaker_id":2,"start_time":2458.57,"speaker_name":"bwillans"},{"text":"Yeah, and I know we''ve talked about that too, Barb.","index":668,"end_time":2469.45,"speaker_id":0,"start_time":2467.05,"speaker_name":"Tristan Pelligrino"},{"text":"I think the.","index":669,"end_time":2470.81,"speaker_id":0,"start_time":2470.01,"speaker_name":"Tristan Pelligrino"},{"text":"We could still roll with that.","index":670,"end_time":2474.21,"speaker_id":0,"start_time":2472.49,"speaker_name":"Tristan Pelligrino"},{"text":"That process because I mean that it''s just like whenever we want to cut over the data is probably the big, big question.","index":671,"end_time":2480.33,"speaker_id":0,"start_time":2474.21,"speaker_name":"Tristan Pelligrino"},{"text":"Because even if you''re.","index":672,"end_time":2481.49,"speaker_id":0,"start_time":2480.33,"speaker_name":"Tristan Pelligrino"},{"text":"If you''re routing people through registration and it goes through Marketo at some point in time, whenever we decide that, okay, here''s our list that we''re going to pull in the, you know, we''re going to sync with Salesforce anyway.","index":673,"end_time":2495.18,"speaker_id":0,"start_time":2481.49,"speaker_name":"Tristan Pelligrino"},{"text":"So, like, you know, that''s kind of the source of truth.","index":674,"end_time":2498.94,"speaker_id":0,"start_time":2495.42,"speaker_name":"Tristan Pelligrino"},{"text":"So not sure it.","index":675,"end_time":2504.5,"speaker_id":0,"start_time":2499.019,"speaker_name":"Tristan Pelligrino"},{"text":"It should drive us to have a blackout period or anything.","index":676,"end_time":2509.3,"speaker_id":0,"start_time":2504.5,"speaker_name":"Tristan Pelligrino"},{"text":"It''s just more about standing up, constant contact to do the promotion.","index":677,"end_time":2513.14,"speaker_id":0,"start_time":2509.3,"speaker_name":"Tristan Pelligrino"},{"text":"Still routing them through the forms that you have.","index":678,"end_time":2517.46,"speaker_id":0,"start_time":2513.86,"speaker_name":"Tristan Pelligrino"},{"text":"Yeah.","index":679,"end_time":2518.1,"speaker_id":0,"start_time":2517.62,"speaker_name":"Tristan Pelligrino"},{"text":"Okay.","index":680,"end_time":2518.78,"speaker_id":2,"start_time":2518.26,"speaker_name":"bwillans"},{"text":"So we''re fine.","index":681,"end_time":2519.5,"speaker_id":1,"start_time":2518.78,"speaker_name":"vivian"},{"text":"Okay, good.","index":682,"end_time":2520.38,"speaker_id":1,"start_time":2519.5,"speaker_name":"vivian"},{"text":"All right.","index":683,"end_time":2520.82,"speaker_id":2,"start_time":2520.38,"speaker_name":"bwillans"},{"text":"Okay.","index":684,"end_time":2521.74,"speaker_id":1,"start_time":2521.3,"speaker_name":"vivian"},{"text":"Wonderful.","index":685,"end_time":2522.1,"speaker_id":1,"start_time":2521.74,"speaker_name":"vivian"},{"text":"That''s awesome.","index":686,"end_time":2522.9,"speaker_id":1,"start_time":2522.1,"speaker_name":"vivian"},{"text":"It won''t slow us down, basically.","index":687,"end_time":2526.979,"speaker_id":0,"start_time":2524.98,"speaker_name":"Tristan Pelligrino"},{"text":"Amazing.","index":688,"end_time":2528.26,"speaker_id":1,"start_time":2527.46,"speaker_name":"vivian"},{"text":"Two more things.","index":689,"end_time":2531.78,"speaker_id":1,"start_time":2531.06,"speaker_name":"vivian"},{"text":"The.","index":690,"end_time":2532.06,"speaker_id":1,"start_time":2531.78,"speaker_name":"vivian"},{"text":"The.","index":691,"end_time":2532.42,"speaker_id":1,"start_time":2532.06,"speaker_name":"vivian"},{"text":"So Jess Khan, Barb, she keeps on saying, like, we need to be able to track what was.","index":692,"end_time":2540.43,"speaker_id":1,"start_time":2533.22,"speaker_name":"vivian"},{"text":"What was industry.","index":693,"end_time":2542.27,"speaker_id":1,"start_time":2541.47,"speaker_name":"vivian"},{"text":"Because this year, like 2026 is the year we''re going into vertical, like industry marketing.","index":694,"end_time":2548.11,"speaker_id":1,"start_time":2542.43,"speaker_name":"vivian"},{"text":"And it''s not just food and beverage.","index":695,"end_time":2550.15,"speaker_id":1,"start_time":2548.59,"speaker_name":"vivian"},{"text":"It''s mining.","index":696,"end_time":2550.91,"speaker_id":1,"start_time":2550.15,"speaker_name":"vivian"},{"text":"It''s, you know, other stuff.","index":697,"end_time":2552.43,"speaker_id":1,"start_time":2550.91,"speaker_name":"vivian"},{"text":"And so it''s a very tactical one, but it''s like we just need to make sure that there''s a field in HubSpot that''s got industry that feeds to Salesforce.","index":698,"end_time":2564.09,"speaker_id":1,"start_time":2552.75,"speaker_name":"vivian"},{"text":"That''s it.","index":699,"end_time":2564.65,"speaker_id":2,"start_time":2564.09,"speaker_name":"bwillans"},{"text":"Yeah.","index":700,"end_time":2566.05,"speaker_id":0,"start_time":2565.69,"speaker_name":"Tristan Pelligrino"},{"text":"And we have.","index":701,"end_time":2566.69,"speaker_id":0,"start_time":2566.05,"speaker_name":"Tristan Pelligrino"},{"text":"So HubSpot will provide that automatically.","index":702,"end_time":2568.81,"speaker_id":0,"start_time":2566.69,"speaker_name":"Tristan Pelligrino"},{"text":"So it''ll enrich based on the domain.","index":703,"end_time":2571.29,"speaker_id":0,"start_time":2568.81,"speaker_name":"Tristan Pelligrino"},{"text":"Awesome.","index":704,"end_time":2572.65,"speaker_id":1,"start_time":2572.09,"speaker_name":"vivian"},{"text":"The only thing there, Vivian, is if you have custom industry definitions.","index":705,"end_time":2577.37,"speaker_id":0,"start_time":2572.97,"speaker_name":"Tristan Pelligrino"},{"text":"So HubSpot''s gonna.","index":706,"end_time":2579.13,"speaker_id":0,"start_time":2577.85,"speaker_name":"Tristan Pelligrino"},{"text":"We don''t.","index":707,"end_time":2580.33,"speaker_id":1,"start_time":2579.69,"speaker_name":"vivian"},{"text":"Okay.","index":708,"end_time":2581.05,"speaker_id":0,"start_time":2580.57,"speaker_name":"Tristan Pelligrino"},{"text":"Because they''re gonna pull from.","index":709,"end_time":2582.29,"speaker_id":0,"start_time":2581.05,"speaker_name":"Tristan Pelligrino"},{"text":"It''s basically gonna be clear bit essentially powered by that.","index":710,"end_time":2585.13,"speaker_id":0,"start_time":2582.29,"speaker_name":"Tristan Pelligrino"},{"text":"That data.","index":711,"end_time":2586.01,"speaker_id":0,"start_time":2585.37,"speaker_name":"Tristan Pelligrino"},{"text":"We can also, you know, import additional industry definitions like if there''s another source or something.","index":712,"end_time":2594.95,"speaker_id":0,"start_time":2587.53,"speaker_name":"Tristan Pelligrino"},{"text":"Like if you have further clarification from another data, like Clay, sometimes we''ll go out there, we''ll get an industry definition that''s a little bit more specific and we''ll pull that in.","index":713,"end_time":2606.35,"speaker_id":0,"start_time":2594.95,"speaker_name":"Tristan Pelligrino"},{"text":"But there is already a field there and that''d be pretty straightforward to map the.","index":714,"end_time":2611.43,"speaker_id":0,"start_time":2607.31,"speaker_name":"Tristan Pelligrino"},{"text":"The account level from Salesforce to HubSpot out of the box.","index":715,"end_time":2615.64,"speaker_id":0,"start_time":2611.43,"speaker_name":"Tristan Pelligrino"},{"text":"Fantastic.","index":716,"end_time":2618.12,"speaker_id":1,"start_time":2617.32,"speaker_name":"vivian"},{"text":"And then the last thing I had was just jumping back to number two.","index":717,"end_time":2621.72,"speaker_id":1,"start_time":2618.6,"speaker_name":"vivian"},{"text":"I''m just reflecting a little bit on the communications plan for rolling this out as well.","index":718,"end_time":2628.6,"speaker_id":1,"start_time":2623.48,"speaker_name":"vivian"},{"text":"I can probably put some thoughts together on that to share with you guys.","index":719,"end_time":2633.96,"speaker_id":1,"start_time":2630.599,"speaker_name":"vivian"},{"text":"But.","index":720,"end_time":2634.28,"speaker_id":1,"start_time":2633.96,"speaker_name":"vivian"},{"text":"But it''s also related to all the forms that are currently in Marketo.","index":721,"end_time":2639.68,"speaker_id":1,"start_time":2634.52,"speaker_name":"vivian"},{"text":"So I. I did account myself and there was like, more.","index":722,"end_time":2645.17,"speaker_id":1,"start_time":2639.68,"speaker_name":"vivian"},{"text":"So there''s obviously the inmarket.","index":723,"end_time":2649.57,"speaker_id":1,"start_time":2645.57,"speaker_name":"vivian"},{"text":"So there''s obviously the Hawk referral form.","index":724,"end_time":2651.89,"speaker_id":1,"start_time":2649.73,"speaker_name":"vivian"},{"text":"Referral form.","index":725,"end_time":2653.09,"speaker_id":1,"start_time":2652.21,"speaker_name":"vivian"},{"text":"There''s also, I don''t know if you guys are aware, a customer service referral form and a professional services referral form.","index":726,"end_time":2660.85,"speaker_id":1,"start_time":2653.17,"speaker_name":"vivian"},{"text":"So there''s four referral forms that we''re going to need to, I guess, rewire and redo from HubSpot to Salesforce and then probably send the link to those teams to be like, hey, here''s your new 2026 referral form and workflow to do stuff.","index":727,"end_time":2680.9,"speaker_id":1,"start_time":2660.93,"speaker_name":"vivian"},{"text":"So just wanted to mention that.","index":728,"end_time":2683.78,"speaker_id":1,"start_time":2681.7,"speaker_name":"vivian"},{"text":"And I also, you know, given that we''re about to do changes, like, would it make sense for.","index":729,"end_time":2689.7,"speaker_id":1,"start_time":2684.82,"speaker_name":"vivian"},{"text":"And I''m happy to volunteer myself for this one to go back to those teams and say, hey, this is your current referral form.","index":730,"end_time":2696.18,"speaker_id":1,"start_time":2689.78,"speaker_name":"vivian"},{"text":"Are we missing anything?","index":731,"end_time":2697.5,"speaker_id":1,"start_time":2696.58,"speaker_name":"vivian"},{"text":"Do we want to remove or add anything?","index":732,"end_time":2699.3,"speaker_id":1,"start_time":2697.5,"speaker_name":"vivian"},{"text":"It''s.","index":733,"end_time":2699.7,"speaker_id":1,"start_time":2699.3,"speaker_name":"vivian"},{"text":"It''s a chance to kind of give it a redo.","index":734,"end_time":2701.78,"speaker_id":1,"start_time":2699.7,"speaker_name":"vivian"},{"text":"Right.","index":735,"end_time":2702.1,"speaker_id":1,"start_time":2701.78,"speaker_name":"vivian"},{"text":"So I just wanted to make sure we didn''t lose that opportunity to.","index":736,"end_time":2705.38,"speaker_id":1,"start_time":2702.1,"speaker_name":"vivian"},{"text":"To revisit that.","index":737,"end_time":2706.9,"speaker_id":1,"start_time":2705.78,"speaker_name":"vivian"},{"text":"Yeah, for sure.","index":738,"end_time":2709.78,"speaker_id":0,"start_time":2708.9,"speaker_name":"Tristan Pelligrino"},{"text":"I know on the referral forms we see those in Marketo.","index":739,"end_time":2712.739,"speaker_id":0,"start_time":2710.1,"speaker_name":"Tristan Pelligrino"},{"text":"Where are they embedded in a WordPress page?","index":740,"end_time":2716.58,"speaker_id":0,"start_time":2712.9,"speaker_name":"Tristan Pelligrino"},{"text":"Barb, do you know, like, I can see the entries in Marketo.","index":741,"end_time":2720.3,"speaker_id":0,"start_time":2716.58,"speaker_name":"Tristan Pelligrino"},{"text":"I''m trying to figure out where.","index":742,"end_time":2721.22,"speaker_id":0,"start_time":2720.3,"speaker_name":"Tristan Pelligrino"},{"text":"Yeah, I think they must be.","index":743,"end_time":2725.31,"speaker_id":2,"start_time":2722.19,"speaker_name":"bwillans"},{"text":"They must be.","index":744,"end_time":2727.79,"speaker_id":2,"start_time":2726.91,"speaker_name":"bwillans"},{"text":"I''m not sure, but I know they originate.","index":745,"end_time":2731.15,"speaker_id":2,"start_time":2728.67,"speaker_name":"bwillans"},{"text":"But they have to be embedded in WordPress to get the information.","index":746,"end_time":2738.59,"speaker_id":2,"start_time":2731.63,"speaker_name":"bwillans"},{"text":"But I can double check for you.","index":747,"end_time":2740.43,"speaker_id":2,"start_time":2738.67,"speaker_name":"bwillans"},{"text":"Yeah, and we can check on that.","index":748,"end_time":2742.27,"speaker_id":0,"start_time":2740.59,"speaker_name":"Tristan Pelligrino"},{"text":"It''s a good question.","index":749,"end_time":2743.79,"speaker_id":0,"start_time":2742.91,"speaker_name":"Tristan Pelligrino"},{"text":"In that case, Vivian, the experience or the URL wouldn''t even have to change on their side.","index":750,"end_time":2751.23,"speaker_id":0,"start_time":2745.07,"speaker_name":"Tristan Pelligrino"},{"text":"Even better.","index":751,"end_time":2752.4,"speaker_id":1,"start_time":2751.84,"speaker_name":"vivian"},{"text":"Yeah, you just swap out the form.","index":752,"end_time":2754.72,"speaker_id":0,"start_time":2752.88,"speaker_name":"Tristan Pelligrino"},{"text":"Then maybe we don''t need to go back and ask if we need to change it.","index":753,"end_time":2759.32,"speaker_id":1,"start_time":2756.48,"speaker_name":"vivian"},{"text":"If that''s the.","index":754,"end_time":2760.24,"speaker_id":1,"start_time":2759.32,"speaker_name":"vivian"},{"text":"I''m like, that will save me four meetings.","index":755,"end_time":2762.2,"speaker_id":1,"start_time":2760.48,"speaker_name":"vivian"},{"text":"I don''t want to have four meetings.","index":756,"end_time":2763.44,"speaker_id":1,"start_time":2762.2,"speaker_name":"vivian"},{"text":"It might be as simple as just like literally replacing it.","index":757,"end_time":2767.559,"speaker_id":0,"start_time":2764.24,"speaker_name":"Tristan Pelligrino"},{"text":"Oh, you guys are the best.","index":758,"end_time":2769.16,"speaker_id":1,"start_time":2767.559,"speaker_name":"vivian"},{"text":"I love it.","index":759,"end_time":2769.84,"speaker_id":2,"start_time":2769.16,"speaker_name":"bwillans"},{"text":"I love how you make things seamless.","index":760,"end_time":2771.6,"speaker_id":1,"start_time":2769.84,"speaker_name":"vivian"},{"text":"Okay, we''ll try.","index":761,"end_time":2772.88,"speaker_id":0,"start_time":2771.84,"speaker_name":"Tristan Pelligrino"},{"text":"We''ll double check, though, you know, but I think that''s what I would suspect.","index":762,"end_time":2776.36,"speaker_id":0,"start_time":2772.88,"speaker_name":"Tristan Pelligrino"},{"text":"So amazing.","index":763,"end_time":2777.6,"speaker_id":1,"start_time":2776.36,"speaker_name":"vivian"},{"text":"That''s it from my side.","index":764,"end_time":2780.84,"speaker_id":1,"start_time":2779.6,"speaker_name":"vivian"},{"text":"Thank you so much for taking all my questions and whatnot.","index":765,"end_time":2786,"speaker_id":1,"start_time":2780.84,"speaker_name":"vivian"},{"text":"Yeah, yeah, for sure.","index":766,"end_time":2787.76,"speaker_id":0,"start_time":2786.48,"speaker_name":"Tristan Pelligrino"},{"text":"Hopefully your ride is going well.","index":767,"end_time":2790.48,"speaker_id":0,"start_time":2788.48,"speaker_name":"Tristan Pelligrino"},{"text":"It''s been going smooth so far.","index":768,"end_time":2793.68,"speaker_id":0,"start_time":2791.68,"speaker_name":"Tristan Pelligrino"},{"text":"Well, Barb, we have some of your questions here.","index":769,"end_time":2797.68,"speaker_id":0,"start_time":2794.079,"speaker_name":"Tristan Pelligrino"},{"text":"Vivian, do you want to Stay on or do you want us to go through Barb''s?","index":770,"end_time":2800.8,"speaker_id":0,"start_time":2797.68,"speaker_name":"Tristan Pelligrino"},{"text":"What are you thinking there?","index":771,"end_time":2801.84,"speaker_id":0,"start_time":2800.88,"speaker_name":"Tristan Pelligrino"},{"text":"Keep going through the.","index":772,"end_time":2804.97,"speaker_id":0,"start_time":2804.09,"speaker_name":"Tristan Pelligrino"},{"text":"The top of the document.","index":773,"end_time":2806.01,"speaker_id":0,"start_time":2804.97,"speaker_name":"Tristan Pelligrino"},{"text":"Let''s keep.","index":774,"end_time":2806.93,"speaker_id":1,"start_time":2806.41,"speaker_name":"vivian"},{"text":"Let''s keep going.","index":775,"end_time":2807.81,"speaker_id":1,"start_time":2806.93,"speaker_name":"vivian"},{"text":"I''m gonna drop off at.","index":776,"end_time":2808.97,"speaker_id":1,"start_time":2807.81,"speaker_name":"vivian"},{"text":"At the 30, but, yeah, happy to stay on.","index":777,"end_time":2812.81,"speaker_id":1,"start_time":2809.37,"speaker_name":"vivian"},{"text":"And.","index":778,"end_time":2813.37,"speaker_id":1,"start_time":2812.97,"speaker_name":"vivian"},{"text":"Yeah, thank you again.","index":779,"end_time":2815.61,"speaker_id":1,"start_time":2814.73,"speaker_name":"vivian"},{"text":"Yeah, for sure.","index":780,"end_time":2817.13,"speaker_id":0,"start_time":2816.01,"speaker_name":"Tristan Pelligrino"},{"text":"All right, so these are rolling to.","index":781,"end_time":2819.97,"speaker_id":0,"start_time":2818.09,"speaker_name":"Tristan Pelligrino"},{"text":"The topical now that we''ve gone through Viv, so I think these should be short but really good stuff to have.","index":782,"end_time":2826.41,"speaker_id":2,"start_time":2819.97,"speaker_name":"bwillans"},{"text":"All right, so, yes, we talked about alignment at the top.","index":783,"end_time":2831.26,"speaker_id":0,"start_time":2827.69,"speaker_name":"Tristan Pelligrino"},{"text":"Mirabor.","index":784,"end_time":2831.98,"speaker_id":0,"start_time":2831.26,"speaker_name":"Tristan Pelligrino"},{"text":"It sounds like we''ll get that shared in some form.","index":785,"end_time":2836.14,"speaker_id":0,"start_time":2831.98,"speaker_name":"Tristan Pelligrino"},{"text":"Whether it''s an image, screenshot, an iPhone photo or something, we''ll look at that in some format.","index":786,"end_time":2842.46,"speaker_id":0,"start_time":2836.14,"speaker_name":"Tristan Pelligrino"},{"text":"And then the next piece, the lead scoring component here, you walk us through this a little bit, Barb.","index":787,"end_time":2851.34,"speaker_id":0,"start_time":2843.02,"speaker_name":"Tristan Pelligrino"},{"text":"Yes, we talked about that a little bit.","index":788,"end_time":2853.66,"speaker_id":2,"start_time":2851.82,"speaker_name":"bwillans"},{"text":"So everything goes into Marketo and then we score.","index":789,"end_time":2856.66,"speaker_id":2,"start_time":2853.66,"speaker_name":"bwillans"},{"text":"It goes into Salesforce.","index":790,"end_time":2858.06,"speaker_id":2,"start_time":2856.66,"speaker_name":"bwillans"},{"text":"I''m not confident that it comes back, you know, correctly.","index":791,"end_time":2863.25,"speaker_id":2,"start_time":2858.65,"speaker_name":"bwillans"},{"text":"So I, you know, I talked to Justin and Maria and.","index":792,"end_time":2867.37,"speaker_id":2,"start_time":2863.25,"speaker_name":"bwillans"},{"text":"And Kyle, but we want to make sure that we don''t lose that.","index":793,"end_time":2872.49,"speaker_id":2,"start_time":2868.01,"speaker_name":"bwillans"},{"text":"That information, that behavior.","index":794,"end_time":2874.33,"speaker_id":2,"start_time":2872.57,"speaker_name":"bwillans"},{"text":"And so I''m not sure, to be honest with you, and, and we should capture the behavior of the people that.","index":795,"end_time":2881.13,"speaker_id":2,"start_time":2874.81,"speaker_name":"bwillans"},{"text":"I know that I see the points coming into Salesforce, but then we kind of.","index":796,"end_time":2885.77,"speaker_id":2,"start_time":2881.45,"speaker_name":"bwillans"},{"text":"We lose the funnel.","index":797,"end_time":2887.78,"speaker_id":2,"start_time":2886.5,"speaker_name":"bwillans"},{"text":"So I asked Vivian to kind of go out to Graziti, who''s a great partner of ours, they''re in India, and just take a look at a couple of lists, because this.","index":798,"end_time":2899.62,"speaker_id":2,"start_time":2888.9,"speaker_name":"bwillans"},{"text":"This, when you see the example here, it''s in our strategy for the next year to say, well, can you pull these lists for us?","index":799,"end_time":2907.18,"speaker_id":2,"start_time":2899.94,"speaker_name":"bwillans"},{"text":"Like, these are solid lists that we can market to, and we want to pull those lists.","index":800,"end_time":2912.91,"speaker_id":2,"start_time":2907.18,"speaker_name":"bwillans"},{"text":"I don''t want to put them in a constant contact, but I, I''d like to have those lists that are solid to be able to hand over to you.","index":801,"end_time":2918.91,"speaker_id":2,"start_time":2912.91,"speaker_name":"bwillans"},{"text":"Now, my question is, do you need us to do that, Want us to do that?","index":802,"end_time":2924.67,"speaker_id":2,"start_time":2918.99,"speaker_name":"bwillans"},{"text":"Is it.","index":803,"end_time":2925.31,"speaker_id":2,"start_time":2924.67,"speaker_name":"bwillans"},{"text":"Is it helpful.","index":804,"end_time":2926.51,"speaker_id":2,"start_time":2925.39,"speaker_name":"bwillans"},{"text":"If, like, you specifically don''t want to lose these lists?","index":805,"end_time":2935.99,"speaker_id":0,"start_time":2931.55,"speaker_name":"Tristan Pelligrino"},{"text":"Is that the.","index":806,"end_time":2936.55,"speaker_id":0,"start_time":2935.99,"speaker_name":"Tristan Pelligrino"},{"text":"The main thing?","index":807,"end_time":2937.23,"speaker_id":0,"start_time":2936.55,"speaker_name":"Tristan Pelligrino"},{"text":"I don''t want to lose the list, but these lists are solid.","index":808,"end_time":2940.77,"speaker_id":2,"start_time":2937.93,"speaker_name":"bwillans"},{"text":"So I want to maintain, I guess, the behavior and the tasks and the comments and everything that maybe, maybe this is not a thing.","index":809,"end_time":2950.25,"speaker_id":2,"start_time":2940.77,"speaker_name":"bwillans"},{"text":"Like, maybe we can just go to Salesforce, pull these exact lists.","index":810,"end_time":2954.33,"speaker_id":2,"start_time":2950.33,"speaker_name":"bwillans"},{"text":"But I don''t want to lose it between Marketo and Salesforce, and.","index":811,"end_time":2958.49,"speaker_id":2,"start_time":2955.37,"speaker_name":"bwillans"},{"text":"And right now I, I don''t know if everything is retained between the two.","index":812,"end_time":2962.25,"speaker_id":2,"start_time":2958.49,"speaker_name":"bwillans"},{"text":"Yeah.","index":813,"end_time":2963.74,"speaker_id":0,"start_time":2963.54,"speaker_name":"Tristan Pelligrino"},{"text":"And is there any other Data bar.","index":814,"end_time":2965.22,"speaker_id":0,"start_time":2963.74,"speaker_name":"Tristan Pelligrino"},{"text":"Are they just like a member of this list or is there other information that we would need?","index":815,"end_time":2971.42,"speaker_id":0,"start_time":2965.3,"speaker_name":"Tristan Pelligrino"},{"text":"Because we could, we could just replicate this in HubSpot, literally call it the same thing and just make sure that the, the contact records are in that list.","index":816,"end_time":2979.54,"speaker_id":0,"start_time":2971.42,"speaker_name":"Tristan Pelligrino"},{"text":"But is there.","index":817,"end_time":2980.82,"speaker_id":2,"start_time":2980.18,"speaker_name":"bwillans"},{"text":"Is there something else maybe that.","index":818,"end_time":2982.58,"speaker_id":0,"start_time":2980.82,"speaker_name":"Tristan Pelligrino"},{"text":"That we would miss there?","index":819,"end_time":2984.58,"speaker_id":0,"start_time":2983.3,"speaker_name":"Tristan Pelligrino"},{"text":"Perhaps not, but I don''t know.","index":820,"end_time":2988.34,"speaker_id":2,"start_time":2986.5,"speaker_name":"bwillans"},{"text":"I think it might be there.","index":821,"end_time":2990.19,"speaker_id":2,"start_time":2989.31,"speaker_name":"bwillans"},{"text":"But that''s why I asked Viv to take a look, to take.","index":822,"end_time":2993.95,"speaker_id":2,"start_time":2990.19,"speaker_name":"bwillans"},{"text":"Do a scrub against the two.","index":823,"end_time":2996.15,"speaker_id":2,"start_time":2993.95,"speaker_name":"bwillans"},{"text":"Just to maybe do a test to say, you know, here''s 1800 people.","index":824,"end_time":3000.67,"speaker_id":2,"start_time":2996.15,"speaker_name":"bwillans"},{"text":"Is it exacting the same fields?","index":825,"end_time":3003.87,"speaker_id":2,"start_time":3000.67,"speaker_name":"bwillans"},{"text":"And I don''t know that right now.","index":826,"end_time":3005.55,"speaker_id":2,"start_time":3004.03,"speaker_name":"bwillans"},{"text":"Okay, well, we could go into those lists and these are the exact names in Marketo.","index":827,"end_time":3010.19,"speaker_id":0,"start_time":3006.19,"speaker_name":"Tristan Pelligrino"},{"text":"Yeah, we can just see they''re not.","index":828,"end_time":3013.51,"speaker_id":0,"start_time":3010.35,"speaker_name":"Tristan Pelligrino"},{"text":"The exact names, but you can do a search.","index":829,"end_time":3015.63,"speaker_id":2,"start_time":3013.51,"speaker_name":"bwillans"},{"text":"But, but Graziti is.","index":830,"end_time":3017.75,"speaker_id":2,"start_time":3015.79,"speaker_name":"bwillans"},{"text":"They''re great people.","index":831,"end_time":3018.55,"speaker_id":2,"start_time":3017.75,"speaker_name":"bwillans"},{"text":"They''re.","index":832,"end_time":3018.87,"speaker_id":2,"start_time":3018.55,"speaker_name":"bwillans"},{"text":"They''re going to come back with those slugs that you can search on if you want to wait until Monday or Tuesday.","index":833,"end_time":3025.81,"speaker_id":2,"start_time":3018.87,"speaker_name":"bwillans"},{"text":"But yeah, they''re good.","index":834,"end_time":3026.81,"speaker_id":2,"start_time":3025.81,"speaker_name":"bwillans"},{"text":"Yeah, that''d be fine.","index":835,"end_time":3027.85,"speaker_id":0,"start_time":3026.97,"speaker_name":"Tristan Pelligrino"},{"text":"If you want to give us those and say, hey, these are important lists to us and we want to make sure that they''re either retained in HubSpot.","index":836,"end_time":3035.21,"speaker_id":0,"start_time":3027.85,"speaker_name":"Tristan Pelligrino"},{"text":"Do these need to be tagged or visible in Salesforce at all or how is that done now?","index":837,"end_time":3042.49,"speaker_id":0,"start_time":3035.77,"speaker_name":"Tristan Pelligrino"},{"text":"Because now it''s just like rev.","index":838,"end_time":3045.05,"speaker_id":0,"start_time":3043.61,"speaker_name":"Tristan Pelligrino"},{"text":"It''s a source, right?","index":839,"end_time":3046.25,"speaker_id":0,"start_time":3045.05,"speaker_name":"Tristan Pelligrino"},{"text":"As far if, like the list source is in.","index":840,"end_time":3050.24,"speaker_id":0,"start_time":3046.25,"speaker_name":"Tristan Pelligrino"},{"text":"In Salesforce now is that what.","index":841,"end_time":3052.96,"speaker_id":0,"start_time":3050.32,"speaker_name":"Tristan Pelligrino"},{"text":"It''s a marketing seed list that we do communications to for a.","index":842,"end_time":3061.2,"speaker_id":2,"start_time":3054.64,"speaker_name":"bwillans"},{"text":"A spray of campaigns and contacts in Salesforce.","index":843,"end_time":3068.48,"speaker_id":2,"start_time":3061.44,"speaker_name":"bwillans"},{"text":"So I think it''s.","index":844,"end_time":3069.84,"speaker_id":2,"start_time":3068.48,"speaker_name":"bwillans"},{"text":"I think there''s some work to do is what I''m saying right now on my side.","index":845,"end_time":3075.6,"speaker_id":2,"start_time":3072.72,"speaker_name":"bwillans"},{"text":"Any first, but.","index":846,"end_time":3076.36,"speaker_id":2,"start_time":3075.6,"speaker_name":"bwillans"},{"text":"Yeah, but let me.","index":847,"end_time":3077.28,"speaker_id":2,"start_time":3076.36,"speaker_name":"bwillans"},{"text":"Yeah, but Barb, I think it''s a brilliant idea to pull these lists out so, so that when we look at this, when we look at the Salesforce list, we''re like, are they mapping at least 90?","index":848,"end_time":3088.52,"speaker_id":1,"start_time":3077.88,"speaker_name":"vivian"},{"text":"Do you know what I mean?","index":849,"end_time":3090.4,"speaker_id":1,"start_time":3089.48,"speaker_name":"vivian"},{"text":"Because if they''re like, why then we''re.","index":850,"end_time":3093.88,"speaker_id":1,"start_time":3090.4,"speaker_name":"vivian"},{"text":"Like, yeah, I''m not sure right now.","index":851,"end_time":3097.4,"speaker_id":2,"start_time":3093.88,"speaker_name":"bwillans"},{"text":"Because it''s all valid.","index":852,"end_time":3098.8,"speaker_id":2,"start_time":3097.4,"speaker_name":"bwillans"},{"text":"Like, these are what.","index":853,"end_time":3099.88,"speaker_id":2,"start_time":3098.8,"speaker_name":"bwillans"},{"text":"We started with this because 100 valid.","index":854,"end_time":3102.4,"speaker_id":2,"start_time":3099.88,"speaker_name":"bwillans"},{"text":"So I don''t want to miss any.","index":855,"end_time":3103.76,"speaker_id":2,"start_time":3102.4,"speaker_name":"bwillans"},{"text":"Anything in any of this.","index":856,"end_time":3105.59,"speaker_id":2,"start_time":3103.99,"speaker_name":"bwillans"},{"text":"I just, I''m hesitating because I.","index":857,"end_time":3108.39,"speaker_id":2,"start_time":3105.99,"speaker_name":"bwillans"},{"text":"Because I really don''t know in the field.","index":858,"end_time":3109.99,"speaker_id":2,"start_time":3108.39,"speaker_name":"bwillans"},{"text":"So we started with these because they''re small list, but they are gold.","index":859,"end_time":3113.51,"speaker_id":2,"start_time":3109.99,"speaker_name":"bwillans"},{"text":"So we want to make sure that we.","index":860,"end_time":3115.35,"speaker_id":2,"start_time":3113.91,"speaker_name":"bwillans"},{"text":"We capture them.","index":861,"end_time":3116.39,"speaker_id":2,"start_time":3115.51,"speaker_name":"bwillans"},{"text":"And Bar, is it the.","index":862,"end_time":3117.47,"speaker_id":0,"start_time":3116.55,"speaker_name":"Tristan Pelligrino"},{"text":"Is it the contact or you''re saying like these are valid contacts that are in this list or are you saying like the, the list.","index":863,"end_time":3122.55,"speaker_id":0,"start_time":3117.47,"speaker_name":"Tristan Pelligrino"},{"text":"We need to make sure that we know which people are in this list.","index":864,"end_time":3127.43,"speaker_id":0,"start_time":3123.43,"speaker_name":"Tristan Pelligrino"},{"text":"Which one?","index":865,"end_time":3128.39,"speaker_id":0,"start_time":3127.75,"speaker_name":"Tristan Pelligrino"},{"text":"Does that make sense what I''m asking or it does.","index":866,"end_time":3132.24,"speaker_id":0,"start_time":3129.52,"speaker_name":"Tristan Pelligrino"},{"text":"So it may be two different, different sides here, but when I look at Mercado and I look at these lists, these people are these, these contacts are engaged.","index":867,"end_time":3143.28,"speaker_id":2,"start_time":3132.24,"speaker_name":"bwillans"},{"text":"They''re correct.","index":868,"end_time":3144.64,"speaker_id":2,"start_time":3143.76,"speaker_name":"bwillans"},{"text":"They''re right.","index":869,"end_time":3145.36,"speaker_id":2,"start_time":3144.72,"speaker_name":"bwillans"},{"text":"They''re.","index":870,"end_time":3146.28,"speaker_id":2,"start_time":3145.84,"speaker_name":"bwillans"},{"text":"They''re speaking to salesforce.com so when we market to them that I know that they are correct and we''re going to bring them over to HubSpot.","index":871,"end_time":3153.84,"speaker_id":2,"start_time":3146.28,"speaker_name":"bwillans"},{"text":"Okay, gotcha.","index":872,"end_time":3155.61,"speaker_id":0,"start_time":3154.16,"speaker_name":"Tristan Pelligrino"},{"text":"Do we need to maintain these.","index":873,"end_time":3158.25,"speaker_id":0,"start_time":3156.73,"speaker_name":"Tristan Pelligrino"},{"text":"But let''s jump in.","index":874,"end_time":3161.13,"speaker_id":2,"start_time":3160.01,"speaker_name":"bwillans"},{"text":"No.","index":875,"end_time":3163.73,"speaker_id":2,"start_time":3163.37,"speaker_name":"bwillans"},{"text":"Nothing more to add.","index":876,"end_time":3165.85,"speaker_id":1,"start_time":3163.73,"speaker_name":"vivian"},{"text":"It''s, it''s interesting to me.","index":877,"end_time":3168.89,"speaker_id":1,"start_time":3167.05,"speaker_name":"vivian"},{"text":"It''s just a different approach of, of determining our list.","index":878,"end_time":3172.21,"speaker_id":1,"start_time":3168.89,"speaker_name":"vivian"},{"text":"Like one is using Salesforce as a source of truth.","index":879,"end_time":3175.45,"speaker_id":1,"start_time":3172.21,"speaker_name":"vivian"},{"text":"This one is using what we''ve been using to date.","index":880,"end_time":3178.85,"speaker_id":1,"start_time":3175.69,"speaker_name":"vivian"},{"text":"Like this has been.","index":881,"end_time":3179.77,"speaker_id":1,"start_time":3178.85,"speaker_name":"vivian"},{"text":"These have been the practical list that we''ve been sending content and marketing to.","index":882,"end_time":3186.21,"speaker_id":1,"start_time":3179.77,"speaker_name":"vivian"},{"text":"And so some comparison of the two is a really makes a lot of sense.","index":883,"end_time":3192.45,"speaker_id":1,"start_time":3186.85,"speaker_name":"vivian"},{"text":"Just a sanity to check what the final list is.","index":884,"end_time":3195.33,"speaker_id":1,"start_time":3192.45,"speaker_name":"vivian"},{"text":"Oh, perfect.","index":885,"end_time":3197.01,"speaker_id":2,"start_time":3196.05,"speaker_name":"bwillans"},{"text":"Are these dynamic lists or are they a point in time?","index":886,"end_time":3200.61,"speaker_id":0,"start_time":3197.57,"speaker_name":"Tristan Pelligrino"},{"text":"Dynamic.","index":887,"end_time":3202.21,"speaker_id":2,"start_time":3201.49,"speaker_name":"bwillans"},{"text":"Are they dynamic?","index":888,"end_time":3203.77,"speaker_id":1,"start_time":3202.93,"speaker_name":"vivian"},{"text":"Okay, they are.","index":889,"end_time":3204.65,"speaker_id":2,"start_time":3203.77,"speaker_name":"bwillans"},{"text":"Yeah, they are.","index":890,"end_time":3205.49,"speaker_id":2,"start_time":3204.65,"speaker_name":"bwillans"},{"text":"So do we know how people enter these lists?","index":891,"end_time":3209.55,"speaker_id":0,"start_time":3205.81,"speaker_name":"Tristan Pelligrino"},{"text":"Like do we, are we comfortable with like that definition?","index":892,"end_time":3212.87,"speaker_id":0,"start_time":3210.35,"speaker_name":"Tristan Pelligrino"},{"text":"Like, because the whims classic customer.","index":893,"end_time":3215.67,"speaker_id":0,"start_time":3212.87,"speaker_name":"Tristan Pelligrino"},{"text":"Seems like it might be point in time but, but maybe not.","index":894,"end_time":3218.51,"speaker_id":0,"start_time":3215.67,"speaker_name":"Tristan Pelligrino"},{"text":"I don''t know.","index":895,"end_time":3219.55,"speaker_id":0,"start_time":3218.83,"speaker_name":"Tristan Pelligrino"},{"text":"Like when did, when do they get added to that?","index":896,"end_time":3222.35,"speaker_id":0,"start_time":3219.55,"speaker_name":"Tristan Pelligrino"},{"text":"Yeah, I think we have some work to do on that, to be honest with you.","index":897,"end_time":3227.23,"speaker_id":2,"start_time":3223.47,"speaker_name":"bwillans"},{"text":"Yeah, yeah, let''s, let''s do some work on that.","index":898,"end_time":3231.43,"speaker_id":2,"start_time":3228.59,"speaker_name":"bwillans"},{"text":"But I think that''s top of our priority list to determine.","index":899,"end_time":3234.51,"speaker_id":2,"start_time":3231.43,"speaker_name":"bwillans"},{"text":"Okay.","index":900,"end_time":3235.07,"speaker_id":0,"start_time":3234.51,"speaker_name":"Tristan Pelligrino"},{"text":"Because we can handle that a couple ways.","index":901,"end_time":3238.45,"speaker_id":0,"start_time":3235.41,"speaker_name":"Tristan Pelligrino"},{"text":"We could like Barb, as you know, we could have a dynamic list based on fields or criteria that people would automatically get added.","index":902,"end_time":3246.45,"speaker_id":0,"start_time":3238.45,"speaker_name":"Tristan Pelligrino"},{"text":"Or do we just have a static list one time that we build based on these here.","index":903,"end_time":3253.81,"speaker_id":0,"start_time":3247.01,"speaker_name":"Tristan Pelligrino"},{"text":"And that''s another approach.","index":904,"end_time":3255.21,"speaker_id":0,"start_time":3253.81,"speaker_name":"Tristan Pelligrino"},{"text":"So two different ways.","index":905,"end_time":3256.21,"speaker_id":0,"start_time":3255.21,"speaker_name":"Tristan Pelligrino"},{"text":"It just depends on how we handle it.","index":906,"end_time":3259.25,"speaker_id":0,"start_time":3256.21,"speaker_name":"Tristan Pelligrino"},{"text":"Yeah.","index":907,"end_time":3260.69,"speaker_id":2,"start_time":3260.21,"speaker_name":"bwillans"},{"text":"I think the good news is, is that we have some great lists.","index":908,"end_time":3264.46,"speaker_id":2,"start_time":3261.26,"speaker_name":"bwillans"},{"text":"So we, we just have to make sure we get them in the HubSpot appropriately.","index":909,"end_time":3269.26,"speaker_id":2,"start_time":3265.02,"speaker_name":"bwillans"},{"text":"My.","index":910,"end_time":3270.62,"speaker_id":2,"start_time":3270.22,"speaker_name":"bwillans"},{"text":"It''s not a concern.","index":911,"end_time":3271.74,"speaker_id":2,"start_time":3270.86,"speaker_name":"bwillans"},{"text":"It''s just, it''s an opportunity.","index":912,"end_time":3273.62,"speaker_id":2,"start_time":3271.82,"speaker_name":"bwillans"},{"text":"Right.","index":913,"end_time":3273.86,"speaker_id":2,"start_time":3273.62,"speaker_name":"bwillans"},{"text":"We, we look at Marketo because I, I, I just talked to Blake so many times.","index":914,"end_time":3278.34,"speaker_id":2,"start_time":3273.86,"speaker_name":"bwillans"},{"text":"He''s a really great BDR and his concern and it''s valid.","index":915,"end_time":3283.26,"speaker_id":2,"start_time":3278.34,"speaker_name":"bwillans"},{"text":"He just said I Don''t want to lose anything.","index":916,"end_time":3285.74,"speaker_id":2,"start_time":3283.42,"speaker_name":"bwillans"},{"text":"And when I say lose anything, he doesn''t want to lose anything.","index":917,"end_time":3288.94,"speaker_id":2,"start_time":3285.98,"speaker_name":"bwillans"},{"text":"That''s come over.","index":918,"end_time":3289.58,"speaker_id":2,"start_time":3288.94,"speaker_name":"bwillans"},{"text":"But.","index":919,"end_time":3289.9,"speaker_id":2,"start_time":3289.58,"speaker_name":"bwillans"},{"text":"But let''s say, you know, there''s been a lack of nurture, and we had wonderful activities this week.","index":920,"end_time":3298.09,"speaker_id":2,"start_time":3290.49,"speaker_name":"bwillans"},{"text":"Sorry, I don''t know why I''m losing my voice here, but we had wonderful activities this week.","index":921,"end_time":3302.81,"speaker_id":2,"start_time":3298.73,"speaker_name":"bwillans"},{"text":"And he said, gosh, you know, I. I don''t know about those people, but I want to know, you know, so they may not be an MQL yet, but we just.","index":922,"end_time":3314.17,"speaker_id":2,"start_time":3302.81,"speaker_name":"bwillans"},{"text":"He.","index":923,"end_time":3314.57,"speaker_id":2,"start_time":3314.17,"speaker_name":"bwillans"},{"text":"We just want to make sure that we''re.","index":924,"end_time":3316.57,"speaker_id":2,"start_time":3314.57,"speaker_name":"bwillans"},{"text":"We''re getting that information out of Mercado into HubSpot and Salesforce.","index":925,"end_time":3322.87,"speaker_id":2,"start_time":3316.99,"speaker_name":"bwillans"},{"text":"Right.","index":926,"end_time":3323.23,"speaker_id":2,"start_time":3322.87,"speaker_name":"bwillans"},{"text":"It''s just that.","index":927,"end_time":3324.11,"speaker_id":2,"start_time":3323.31,"speaker_name":"bwillans"},{"text":"That.","index":928,"end_time":3324.51,"speaker_id":2,"start_time":3324.11,"speaker_name":"bwillans"},{"text":"That front end, we just don''t want to lose.","index":929,"end_time":3327.87,"speaker_id":2,"start_time":3324.75,"speaker_name":"bwillans"},{"text":"And he just.","index":930,"end_time":3329.55,"speaker_id":2,"start_time":3327.87,"speaker_name":"bwillans"},{"text":"He was so excited.","index":931,"end_time":3331.15,"speaker_id":2,"start_time":3329.55,"speaker_name":"bwillans"},{"text":"He said, how we go straight to 100.","index":932,"end_time":3333.538,"speaker_id":2,"start_time":3331.15,"speaker_name":"bwillans"},{"text":"100 points, but what about the rest of it?","index":933,"end_time":3335.87,"speaker_id":2,"start_time":3333.642,"speaker_name":"bwillans"},{"text":"And I don''t know, Tristan and Vivian, that we''re just not doing that yet.","index":934,"end_time":3341.15,"speaker_id":2,"start_time":3335.95,"speaker_name":"bwillans"},{"text":"But there''s so much opportunity there to be able to do it.","index":935,"end_time":3344.11,"speaker_id":2,"start_time":3341.15,"speaker_name":"bwillans"},{"text":"Oh, you''re totally right.","index":936,"end_time":3345.67,"speaker_id":1,"start_time":3344.11,"speaker_name":"vivian"},{"text":"So we need to pull all the people in the last maybe four or five months that have been active in the programming that you''ve done to make sure that they''re in our database and their recent activity in the last five months are mapped exactly.","index":937,"end_time":3361.64,"speaker_id":1,"start_time":3345.67,"speaker_name":"vivian"},{"text":"Yeah.","index":938,"end_time":3362.52,"speaker_id":2,"start_time":3362.04,"speaker_name":"bwillans"},{"text":"So I''ve been doing it by the hundreds and putting it into constant contact.","index":939,"end_time":3366.52,"speaker_id":2,"start_time":3362.52,"speaker_name":"bwillans"},{"text":"Tristan.","index":940,"end_time":3367.16,"speaker_id":2,"start_time":3366.68,"speaker_name":"bwillans"},{"text":"And I''ve been pulling it going.","index":941,"end_time":3369,"speaker_id":1,"start_time":3367.56,"speaker_name":"vivian"},{"text":"But I don''t want to populate 17,000.","index":942,"end_time":3373.56,"speaker_id":2,"start_time":3371.24,"speaker_name":"bwillans"},{"text":"I think I''m up to 600, but.","index":943,"end_time":3376.45,"speaker_id":2,"start_time":3374.04,"speaker_name":"bwillans"},{"text":"Yeah.","index":944,"end_time":3377.45,"speaker_id":2,"start_time":3377.09,"speaker_name":"bwillans"},{"text":"Does that make sense to you guys?","index":945,"end_time":3378.49,"speaker_id":2,"start_time":3377.45,"speaker_name":"bwillans"},{"text":"I feel like a light bulb.","index":946,"end_time":3379.49,"speaker_id":2,"start_time":3378.49,"speaker_name":"bwillans"},{"text":"Yes.","index":947,"end_time":3379.89,"speaker_id":1,"start_time":3379.49,"speaker_name":"vivian"},{"text":"No, totally makes sense.","index":948,"end_time":3381.57,"speaker_id":1,"start_time":3379.97,"speaker_name":"vivian"},{"text":"I. I didn''t.","index":949,"end_time":3382.85,"speaker_id":1,"start_time":3381.81,"speaker_name":"vivian"},{"text":"I didn''t think of that.","index":950,"end_time":3383.93,"speaker_id":1,"start_time":3383.01,"speaker_name":"vivian"},{"text":"But that''s really.","index":951,"end_time":3385.73,"speaker_id":1,"start_time":3383.93,"speaker_name":"vivian"},{"text":"Thanks.","index":952,"end_time":3386.61,"speaker_id":2,"start_time":3386.13,"speaker_name":"bwillans"},{"text":"Important.","index":953,"end_time":3387.73,"speaker_id":1,"start_time":3387.33,"speaker_name":"vivian"},{"text":"Thanks, everybody.","index":954,"end_time":3388.77,"speaker_id":2,"start_time":3387.81,"speaker_name":"bwillans"},{"text":"Yeah, yeah.","index":955,"end_time":3389.77,"speaker_id":0,"start_time":3389.01,"speaker_name":"Tristan Pelligrino"},{"text":"You''re losing your voice.","index":956,"end_time":3391.17,"speaker_id":1,"start_time":3389.77,"speaker_name":"vivian"},{"text":"Get some water.","index":957,"end_time":3393.01,"speaker_id":1,"start_time":3392.21,"speaker_name":"vivian"},{"text":"You talk too much this week.","index":958,"end_time":3396.85,"speaker_id":2,"start_time":3395.41,"speaker_name":"bwillans"},{"text":"I''ve talked too much this week.","index":959,"end_time":3398.57,"speaker_id":2,"start_time":3397.09,"speaker_name":"bwillans"},{"text":"No one needs to hear my voice again after this call.","index":960,"end_time":3401.57,"speaker_id":2,"start_time":3398.57,"speaker_name":"bwillans"},{"text":"Trust me.","index":961,"end_time":3402.77,"speaker_id":2,"start_time":3402.05,"speaker_name":"bwillans"},{"text":"Let me.","index":962,"end_time":3405.74,"speaker_id":0,"start_time":3405.46,"speaker_name":"Tristan Pelligrino"},{"text":"We.","index":963,"end_time":3406.02,"speaker_id":0,"start_time":3405.74,"speaker_name":"Tristan Pelligrino"},{"text":"We still have a few minutes.","index":964,"end_time":3407.1,"speaker_id":0,"start_time":3406.02,"speaker_name":"Tristan Pelligrino"},{"text":"I did want to ask about this piece here, if y'' all don''t mind.","index":965,"end_time":3410.34,"speaker_id":0,"start_time":3407.1,"speaker_name":"Tristan Pelligrino"},{"text":"Okay.","index":966,"end_time":3411.62,"speaker_id":2,"start_time":3411.06,"speaker_name":"bwillans"},{"text":"Oh, yeah, it is.","index":967,"end_time":3414.26,"speaker_id":0,"start_time":3412.66,"speaker_name":"Tristan Pelligrino"},{"text":"It sounds like the marketing, once a contact or account is in an opportunity stage.","index":968,"end_time":3419.94,"speaker_id":0,"start_time":3415.06,"speaker_name":"Tristan Pelligrino"},{"text":"So tell me a little bit about this.","index":969,"end_time":3421.3,"speaker_id":0,"start_time":3419.94,"speaker_name":"Tristan Pelligrino"},{"text":"Okay.","index":970,"end_time":3422.26,"speaker_id":2,"start_time":3421.7,"speaker_name":"bwillans"},{"text":"Okay.","index":971,"end_time":3422.82,"speaker_id":1,"start_time":3422.26,"speaker_name":"vivian"},{"text":"So.","index":972,"end_time":3423.7,"speaker_id":2,"start_time":3423.3,"speaker_name":"bwillans"},{"text":"So I met with a Taylor dentist who''s a.","index":973,"end_time":3428.02,"speaker_id":1,"start_time":3425.46,"speaker_name":"vivian"},{"text":"A team lead on the west.","index":974,"end_time":3430.44,"speaker_id":1,"start_time":3429.16,"speaker_name":"vivian"},{"text":"And I said, look, do you want marketing to, like, engage with existing opportunities.","index":975,"end_time":3440.52,"speaker_id":1,"start_time":3430.44,"speaker_name":"vivian"},{"text":"At.","index":976,"end_time":3442.92,"speaker_id":2,"start_time":3442.52,"speaker_name":"bwillans"},{"text":"At different stages?","index":977,"end_time":3444.2,"speaker_id":1,"start_time":3443.16,"speaker_name":"vivian"},{"text":"So the way that we measure, it''s 10 to 10 to 90.","index":978,"end_time":3447.48,"speaker_id":1,"start_time":3444.44,"speaker_name":"vivian"},{"text":"Well, 10 to 100%.","index":979,"end_time":3448.84,"speaker_id":1,"start_time":3447.64,"speaker_name":"vivian"},{"text":"So I think the milestones are 10, 30, 50, 70, 90, and then 100.","index":980,"end_time":3454.28,"speaker_id":1,"start_time":3449.32,"speaker_name":"vivian"},{"text":"That''s how sales measures the opportunity stage.","index":981,"end_time":3458.93,"speaker_id":1,"start_time":3454.77,"speaker_name":"vivian"},{"text":"I''m probably saying it wrong, but like they''re trying to figure out where the deal''s at.","index":982,"end_time":3463.09,"speaker_id":1,"start_time":3459.09,"speaker_name":"vivian"},{"text":"And she basically said, you know what, I want marketing to continue to contact these guys up until they get to 100% because it doesn''t hurt for them to listen to a customer webinar.","index":983,"end_time":3476.41,"speaker_id":1,"start_time":3463.49,"speaker_name":"vivian"},{"text":"It doesn''t hurt for them to get value added information.","index":984,"end_time":3479.25,"speaker_id":1,"start_time":3476.41,"speaker_name":"vivian"},{"text":"So long as we are not randomly sending everyone information.","index":985,"end_time":3485.59,"speaker_id":1,"start_time":3479.57,"speaker_name":"vivian"},{"text":"Like so the thing that I wrote there, Barb, and I''m glad we had a chance to talk about this.","index":986,"end_time":3490.63,"speaker_id":1,"start_time":3485.83,"speaker_name":"vivian"},{"text":"I was just making this up like, so her, her intent was just make sure marketing does segmentation.","index":987,"end_time":3497.189,"speaker_id":1,"start_time":3490.79,"speaker_name":"vivian"},{"text":"Meaning when we do, when we pull lists, we, we can pull like, let''s say we run a campaign that''s more top, top of funnel.","index":988,"end_time":3504.55,"speaker_id":1,"start_time":3497.51,"speaker_name":"vivian"},{"text":"So we would pull like people that are net new people that are existing opportunities from 10% to 30% for top of funnel content, like educational content.","index":989,"end_time":3516.96,"speaker_id":1,"start_time":3504.87,"speaker_name":"vivian"},{"text":"And then like as we''re running other stuff, we can pull existing opportunities in their later stages that are aligned to customer content.","index":990,"end_time":3525.92,"speaker_id":1,"start_time":3517.44,"speaker_name":"vivian"},{"text":"So she just wanted to see some segmentation.","index":991,"end_time":3528.64,"speaker_id":1,"start_time":3526.56,"speaker_name":"vivian"},{"text":"So that was basically it.","index":992,"end_time":3530.64,"speaker_id":1,"start_time":3529.28,"speaker_name":"vivian"},{"text":"Hope that helps.","index":993,"end_time":3533.85,"speaker_id":1,"start_time":3533.05,"speaker_name":"vivian"},{"text":"Yeah, we could do that.","index":994,"end_time":3535.29,"speaker_id":0,"start_time":3534.33,"speaker_name":"Tristan Pelligrino"},{"text":"Basically we''re using the stage of the opportunity and mapping that at the account level.","index":995,"end_time":3543.93,"speaker_id":0,"start_time":3535.37,"speaker_name":"Tristan Pelligrino"},{"text":"Any contacts that reach certain that are associated with an account that has a deal at this stage, then it would, you know, flip a switch or something or turn it off.","index":996,"end_time":3554.09,"speaker_id":0,"start_time":3543.93,"speaker_name":"Tristan Pelligrino"},{"text":"Whether they would or would not be in a list for communications.","index":997,"end_time":3558.89,"speaker_id":0,"start_time":3554.33,"speaker_name":"Tristan Pelligrino"},{"text":"Yeah, yep.","index":998,"end_time":3561.27,"speaker_id":0,"start_time":3559.63,"speaker_name":"Tristan Pelligrino"},{"text":"That can be done for sure.","index":999,"end_time":3562.75,"speaker_id":0,"start_time":3561.27,"speaker_name":"Tristan Pelligrino"},{"text":"Yeah.","index":1000,"end_time":3565.23,"speaker_id":2,"start_time":3564.75,"speaker_name":"bwillans"},{"text":"And this will.","index":1001,"end_time":3566.71,"speaker_id":1,"start_time":3566.03,"speaker_name":"vivian"},{"text":"And again, I saw that magical word in the document.","index":1002,"end_time":3569.47,"speaker_id":1,"start_time":3566.71,"speaker_name":"vivian"},{"text":"This is like multi touch.","index":1003,"end_time":3571.47,"speaker_id":1,"start_time":3569.47,"speaker_name":"vivian"},{"text":"We''ll be able to track it.","index":1004,"end_time":3573.47,"speaker_id":1,"start_time":3572.19,"speaker_name":"vivian"},{"text":"Yeah, for sure.","index":1005,"end_time":3574.75,"speaker_id":0,"start_time":3574.11,"speaker_name":"Tristan Pelligrino"},{"text":"Because you''ll, you''ll get those activities, you know, and that''s the big thing and the other key component to it.","index":1006,"end_time":3580.99,"speaker_id":0,"start_time":3574.75,"speaker_name":"Tristan Pelligrino"},{"text":"And this is just from a marketing standpoint, is there.","index":1007,"end_time":3586.26,"speaker_id":0,"start_time":3580.99,"speaker_name":"Tristan Pelligrino"},{"text":"It''s always about credit or like where.","index":1008,"end_time":3588.66,"speaker_id":0,"start_time":3586.66,"speaker_name":"Tristan Pelligrino"},{"text":"Often it''s just like where did it come from?","index":1009,"end_time":3591.3,"speaker_id":0,"start_time":3588.82,"speaker_name":"Tristan Pelligrino"},{"text":"But like I feel like for you all, if it''s like, hey, an opportunity progressed right in these stages and look at all the activities, that''s really where we, you get the, the influence from a marketing standpoint because it''s not only about just getting someone to fill out a form and get dropped in a database because we all know that that''s just the, that''s just the starting point.","index":1010,"end_time":3614.07,"speaker_id":0,"start_time":3591.62,"speaker_name":"Tristan Pelligrino"},{"text":"That''s not the hard part.","index":1011,"end_time":3615.19,"speaker_id":0,"start_time":3614.07,"speaker_name":"Tristan Pelligrino"},{"text":"That, that''s all the communications afterwards.","index":1012,"end_time":3617.31,"speaker_id":0,"start_time":3615.19,"speaker_name":"Tristan Pelligrino"},{"text":"So.","index":1013,"end_time":3617.71,"speaker_id":0,"start_time":3617.31,"speaker_name":"Tristan Pelligrino"},{"text":"All right.","index":1014,"end_time":3620.91,"speaker_id":0,"start_time":3620.35,"speaker_name":"Tristan Pelligrino"},{"text":"And there''s Some other things that we''ll talk about too, as far as, like, website traffic, all that stuff gets recorded as well.","index":1015,"end_time":3627.31,"speaker_id":0,"start_time":3622.27,"speaker_name":"Tristan Pelligrino"},{"text":"You know, account activity, you know, HubSpot will have a lot of that, that, that you could always reflect once an opportunity goes through.","index":1016,"end_time":3634.55,"speaker_id":0,"start_time":3627.95,"speaker_name":"Tristan Pelligrino"},{"text":"You could even go back and say, okay, what activities occurred, what was the timeline?","index":1017,"end_time":3639.93,"speaker_id":0,"start_time":3634.55,"speaker_name":"Tristan Pelligrino"},{"text":"That''s always interesting to do as well.","index":1018,"end_time":3641.65,"speaker_id":0,"start_time":3639.93,"speaker_name":"Tristan Pelligrino"},{"text":"Kind of do an inventory, so.","index":1019,"end_time":3644.93,"speaker_id":0,"start_time":3641.65,"speaker_name":"Tristan Pelligrino"},{"text":"All right, well, Barb''s lost her voice.","index":1020,"end_time":3647.49,"speaker_id":0,"start_time":3645.73,"speaker_name":"Tristan Pelligrino"},{"text":"Vivian''s in the car.","index":1021,"end_time":3648.61,"speaker_id":0,"start_time":3647.57,"speaker_name":"Tristan Pelligrino"},{"text":"How are we feeling?","index":1022,"end_time":3653.73,"speaker_id":0,"start_time":3652.69,"speaker_name":"Tristan Pelligrino"},{"text":"Pretty, Pretty good.","index":1023,"end_time":3654.69,"speaker_id":0,"start_time":3653.73,"speaker_name":"Tristan Pelligrino"},{"text":"I know we''ve.","index":1024,"end_time":3655.45,"speaker_id":0,"start_time":3654.69,"speaker_name":"Tristan Pelligrino"},{"text":"Yeah.","index":1025,"end_time":3655.89,"speaker_id":1,"start_time":3655.45,"speaker_name":"vivian"},{"text":"Barb, it sounds like you got some things that could come our way, you know, on the life cycle stage and things like that.","index":1026,"end_time":3662.57,"speaker_id":0,"start_time":3656.05,"speaker_name":"Tristan Pelligrino"},{"text":"But I think as far as, like, key next steps, make sure it would be good to have a next meeting with Kyle and Maria to go through some of this, talk through whatever information you can send on the Miro board that would give us some more context.","index":1027,"end_time":3680.26,"speaker_id":0,"start_time":3662.57,"speaker_name":"Tristan Pelligrino"},{"text":"And then after that, you know, I think we, we have to just get into the details in some of these critical fields that we need to make sure are in place and then, you know, we''ll keep moving forward there.","index":1028,"end_time":3691.37,"speaker_id":0,"start_time":3680.26,"speaker_name":"Tristan Pelligrino"},{"text":"But we''re not too far away from, from starting to test some of this stuff and getting into some of the real products.","index":1029,"end_time":3697.21,"speaker_id":0,"start_time":3691.37,"speaker_name":"Tristan Pelligrino"},{"text":"You know, there will still be some other things we have to decide once we run up against something in testing, but, you know, the bulk of it''s been, you know, figured out in a, you know, good collaborative process here, so.","index":1030,"end_time":3709.37,"speaker_id":0,"start_time":3697.21,"speaker_name":"Tristan Pelligrino"},{"text":"I appreciate it.","index":1031,"end_time":3710.17,"speaker_id":0,"start_time":3709.37,"speaker_name":"Tristan Pelligrino"},{"text":"No, it''s good.","index":1032,"end_time":3711.85,"speaker_id":2,"start_time":3710.97,"speaker_name":"bwillans"},{"text":"I. I got some water, so I think I''m better here.","index":1033,"end_time":3714.65,"speaker_id":2,"start_time":3711.85,"speaker_name":"bwillans"},{"text":"Tristan, how.","index":1034,"end_time":3717.44,"speaker_id":2,"start_time":3716.64,"speaker_name":"bwillans"},{"text":"How are we mapping in terms of what you initially thought?","index":1035,"end_time":3721.04,"speaker_id":2,"start_time":3717.44,"speaker_name":"bwillans"},{"text":"Like, are we, are we behind?","index":1036,"end_time":3723.52,"speaker_id":2,"start_time":3721.12,"speaker_name":"bwillans"},{"text":"Are we ahead?","index":1037,"end_time":3724.4,"speaker_id":2,"start_time":3723.68,"speaker_name":"bwillans"},{"text":"Like, what, what is it that you need us to do?","index":1038,"end_time":3728,"speaker_id":2,"start_time":3724.48,"speaker_name":"bwillans"},{"text":"Yeah, big picture.","index":1039,"end_time":3729.72,"speaker_id":0,"start_time":3728.64,"speaker_name":"Tristan Pelligrino"},{"text":"You know, we wanted to have the plan, a lot of this mapped out by the end of.","index":1040,"end_time":3733.2,"speaker_id":0,"start_time":3729.72,"speaker_name":"Tristan Pelligrino"},{"text":"Of November.","index":1041,"end_time":3733.96,"speaker_id":0,"start_time":3733.2,"speaker_name":"Tristan Pelligrino"},{"text":"You know, now we got, we got the HubSpot instance in mid November.","index":1042,"end_time":3737.48,"speaker_id":0,"start_time":3733.96,"speaker_name":"Tristan Pelligrino"},{"text":"And I think I told you, Barb, we didn''t necessarily need that.","index":1043,"end_time":3740.12,"speaker_id":0,"start_time":3737.48,"speaker_name":"Tristan Pelligrino"},{"text":"Right?","index":1044,"end_time":3740.4,"speaker_id":0,"start_time":3740.12,"speaker_name":"Tristan Pelligrino"},{"text":"Like, right, because we had to do this work first because we were in mostly Marketo and Salesforce initially because we know what HubSpot looks like.","index":1045,"end_time":3748.06,"speaker_id":0,"start_time":3740.4,"speaker_name":"Tristan Pelligrino"},{"text":"It''s.","index":1046,"end_time":3748.42,"speaker_id":0,"start_time":3748.06,"speaker_name":"Tristan Pelligrino"},{"text":"It''s a blank canvas and it kind of will look like however we want it to look.","index":1047,"end_time":3752.38,"speaker_id":0,"start_time":3748.42,"speaker_name":"Tristan Pelligrino"},{"text":"So.","index":1048,"end_time":3752.78,"speaker_id":0,"start_time":3752.38,"speaker_name":"Tristan Pelligrino"},{"text":"So now December is really that configuration piece.","index":1049,"end_time":3756.54,"speaker_id":0,"start_time":3753.1,"speaker_name":"Tristan Pelligrino"},{"text":"We''ll do some testing and we can give you some of those clear next steps as to, as to what that looks like.","index":1050,"end_time":3762.38,"speaker_id":0,"start_time":3756.94,"speaker_name":"Tristan Pelligrino"},{"text":"But, you know, we''re marching towards that, like, January, cut over and we can, can talk about exactly what that date looks like.","index":1051,"end_time":3770.19,"speaker_id":0,"start_time":3762.38,"speaker_name":"Tristan Pelligrino"},{"text":"But, I mean, I''m feeling pretty good, you know, timeline as far as where things are right now.","index":1052,"end_time":3774.95,"speaker_id":0,"start_time":3770.19,"speaker_name":"Tristan Pelligrino"},{"text":"We''re not lagging so far on our end too much?","index":1053,"end_time":3777.91,"speaker_id":2,"start_time":3775.43,"speaker_name":"bwillans"},{"text":"No, I don''t.","index":1054,"end_time":3778.91,"speaker_id":0,"start_time":3778.15,"speaker_name":"Tristan Pelligrino"},{"text":"I don''t think so.","index":1055,"end_time":3779.67,"speaker_id":0,"start_time":3778.91,"speaker_name":"Tristan Pelligrino"},{"text":"You know, we have access to the system, so a lot of the questions we have, you know, we''re jumping in and figuring out, like, you know, what would we do in this scenario, you know, And I think as we get through, there will be a few things that we have to flush out that we didn''t catch.","index":1056,"end_time":3795.03,"speaker_id":0,"start_time":3780.55,"speaker_name":"Tristan Pelligrino"},{"text":"But.","index":1057,"end_time":3795.23,"speaker_id":0,"start_time":3795.03,"speaker_name":"Tristan Pelligrino"},{"text":"But.","index":1058,"end_time":3795.54,"speaker_id":0,"start_time":3795.3,"speaker_name":"Tristan Pelligrino"},{"text":"But we''re close for sure.","index":1059,"end_time":3798.42,"speaker_id":0,"start_time":3796.34,"speaker_name":"Tristan Pelligrino"},{"text":"All right, well, thank you so much.","index":1060,"end_time":3801.06,"speaker_id":2,"start_time":3799.22,"speaker_name":"bwillans"},{"text":"And before we close off, Vivian, is there anything that you need after this call that, you know, to feel successful?","index":1061,"end_time":3811.619,"speaker_id":2,"start_time":3801.06,"speaker_name":"bwillans"},{"text":"So.","index":1062,"end_time":3812.42,"speaker_id":2,"start_time":3812.02,"speaker_name":"bwillans"},{"text":"Yeah, no, I think we are in excellent shape.","index":1063,"end_time":3819.38,"speaker_id":1,"start_time":3812.58,"speaker_name":"vivian"},{"text":"I. I will take the homework to just at least put a.","index":1064,"end_time":3825.13,"speaker_id":1,"start_time":3821.46,"speaker_name":"vivian"},{"text":"Put some thoughts on paper around, like the.","index":1065,"end_time":3828.61,"speaker_id":1,"start_time":3825.29,"speaker_name":"vivian"},{"text":"Like, pulling from the Salesforce list and the fields, and then we can work on it next Friday.","index":1066,"end_time":3832.69,"speaker_id":1,"start_time":3828.61,"speaker_name":"vivian"},{"text":"Barb, like, when we meet.","index":1067,"end_time":3834.73,"speaker_id":1,"start_time":3832.69,"speaker_name":"vivian"},{"text":"Yeah, I feel really good.","index":1068,"end_time":3841.29,"speaker_id":1,"start_time":3839.93,"speaker_name":"vivian"},{"text":"Like, it''s.","index":1069,"end_time":3842.53,"speaker_id":1,"start_time":3841.29,"speaker_name":"vivian"},{"text":"It''s again, so clear.","index":1070,"end_time":3844.01,"speaker_id":1,"start_time":3842.53,"speaker_name":"vivian"},{"text":"I haven''t had a.","index":1071,"end_time":3845.77,"speaker_id":1,"start_time":3844.17,"speaker_name":"vivian"},{"text":"An implementation this clear before, so.","index":1072,"end_time":3849.13,"speaker_id":1,"start_time":3846.57,"speaker_name":"vivian"},{"text":"Barb wasn''t joking, Tristan and team, that.","index":1073,"end_time":3852.01,"speaker_id":1,"start_time":3849.21,"speaker_name":"vivian"},{"text":"You guys are the best.","index":1074,"end_time":3853.41,"speaker_id":1,"start_time":3852.45,"speaker_name":"vivian"},{"text":"I really appreciate that.","index":1075,"end_time":3855.57,"speaker_id":0,"start_time":3854.29,"speaker_name":"Tristan Pelligrino"},{"text":"Yeah, you guys are the best.","index":1076,"end_time":3857.61,"speaker_id":1,"start_time":3856.13,"speaker_name":"vivian"},{"text":"Barb has always said that, and I''m.","index":1077,"end_time":3860.53,"speaker_id":1,"start_time":3857.61,"speaker_name":"vivian"},{"text":"I''m equally grateful that we''re working with you.","index":1078,"end_time":3864.77,"speaker_id":1,"start_time":3860.53,"speaker_name":"vivian"},{"text":"Awesome.","index":1079,"end_time":3866.41,"speaker_id":0,"start_time":3865.89,"speaker_name":"Tristan Pelligrino"},{"text":"Well, we.","index":1080,"end_time":3866.73,"speaker_id":0,"start_time":3866.41,"speaker_name":"Tristan Pelligrino"},{"text":"We appreciate that feedback.","index":1081,"end_time":3867.97,"speaker_id":0,"start_time":3866.73,"speaker_name":"Tristan Pelligrino"},{"text":"Yeah, no, Bar has been a great partner of ours.","index":1082,"end_time":3869.97,"speaker_id":0,"start_time":3867.97,"speaker_name":"Tristan Pelligrino"},{"text":"We.","index":1083,"end_time":3870.29,"speaker_id":0,"start_time":3869.97,"speaker_name":"Tristan Pelligrino"},{"text":"Maybe that''s part of it.","index":1084,"end_time":3871.73,"speaker_id":0,"start_time":3870.53,"speaker_name":"Tristan Pelligrino"},{"text":"There''s some shorthand there.","index":1085,"end_time":3873.33,"speaker_id":0,"start_time":3872.05,"speaker_name":"Tristan Pelligrino"},{"text":"We''ve done a lot of these types of activities, so we can move pretty quickly.","index":1086,"end_time":3876.93,"speaker_id":0,"start_time":3873.33,"speaker_name":"Tristan Pelligrino"},{"text":"I know.","index":1087,"end_time":3877.97,"speaker_id":2,"start_time":3877.41,"speaker_name":"bwillans"},{"text":"Wonderful.","index":1088,"end_time":3879.11,"speaker_id":1,"start_time":3878.47,"speaker_name":"vivian"},{"text":"All right, thank you.","index":1089,"end_time":3880.59,"speaker_id":1,"start_time":3879.75,"speaker_name":"vivian"},{"text":"Have a great weekend, everyone.","index":1090,"end_time":3881.75,"speaker_id":1,"start_time":3880.59,"speaker_name":"vivian"},{"text":"Well, thank you, everyone.","index":1091,"end_time":3882.87,"speaker_id":0,"start_time":3881.83,"speaker_name":"Tristan Pelligrino"},{"text":"Chat soon.","index":1092,"end_time":3883.99,"speaker_id":0,"start_time":3883.19,"speaker_name":"Tristan Pelligrino"},{"text":"All right.","index":1093,"end_time":3884.75,"speaker_id":2,"start_time":3884.23,"speaker_name":"bwillans"},{"text":"Take care of.","index":1094,"end_time":3886.06,"speaker_id":